-- KONULAR (111) — ünite başlığına göre eşlenir
insert into public.topics (unit_id, title, sort_order, summary)
select u.id, d.title, d.sort_order, d.summary
from (values
  ('İnsanlığın Hafızası Tarih', 'Tarih Bilimi ve Konusu', 1, 'Tarih; insan topluluklarının geçmişteki faaliyetlerini yer ve zaman göstererek, sebep-sonuç ilişkisi içinde belgelere dayanarak inceleyen sosyal bilimdir. Tarihin konusu, insanların meydana getirdiği siyasi, askerî, sosyal, ekonomik ve kültürel faaliyetlerdir. Tarihî olaylar tekrarlanamadığı için deney ve gözlem yöntemi uygulanamaz. Tarihî bilgiler, olayın yaşandığı dönemin şartları dikkate alınarak değerlendirilmelidir.'),
  ('İnsanlığın Hafızası Tarih', 'Kaynakların Sınıflandırılması', 2, 'Tarihî kaynaklar, geçmiş hakkında bilgi veren belge, buluntu ve materyallerdir. Birinci el kaynaklar olayın yaşandığı döneme ait kitabe, para, ferman ve arkeolojik buluntu gibi kaynaklardır; ikinci el kaynaklar ise bunlardan yararlanılarak sonradan oluşturulan eserlerdir. Kaynaklar sözlü, yazılı, sesli-görüntülü ve gerçek eşya-nesne kaynakları olarak sınıflandırılır. Tarih araştırmalarında kaynakların güvenilirliği ve döneme yakınlığı önemlidir.'),
  ('İnsanlığın Hafızası Tarih', 'Tarihe Yardımcı Bilim Dalları', 3, 'Kronoloji olayları zaman sırasına koyar; coğrafya insan ve mekân ilişkisini inceler; arkeoloji kazılarla maddi kalıntıları ortaya çıkarır. Nümismatik paraları, paleografya eski yazıları, epigrafi ise kitabe ve mezar taşlarındaki yazıları araştırır. Tarih öncesi dönemlerin aydınlatılmasında en çok arkeolojiden yararlanılır. Nümismatik, paleografya ve epigrafi yazılı materyallere dayandığı için tarih öncesi dönemleri aydınlatamaz.'),
  ('Zamanın Taksimi', 'Takvim Sistemlerinin Doğuşu', 1, 'Takvim, zamanın Güneş ve Ay hareketlerine göre gün, hafta, ay ve yıl gibi bölümlere ayrılmasıdır. Toplumlar, hayatlarını en çok etkileyen olayları takvim başlangıcı kabul etmiştir. Ay yılı 354 gün, Güneş yılı ise 365 gün 6 saattir. Yazının icadı, tarih öncesi dönemlerle tarihî dönemleri birbirinden ayıran gelişmedir.'),
  ('Zamanın Taksimi', 'Türklerin Kullandığı Takvimler', 2, 'Türklerin kullandığı ilk takvim Güneş yılına dayanan On İki Hayvanlı Türk Takvimi’dir. Hicrî Takvim ay yılına dayanır, başlangıcı 622 Hicret’tir ve dinî günlerin belirlenmesinde kullanılır. Celâlî Takvim, Melikşah’ın emriyle Ömer Hayyam başkanlığında hazırlanmıştır. Rûmî Takvim Osmanlı’da mali işlerde kullanılmış, Miladî Takvim ise Türkiye’de 1 Ocak 1926’dan itibaren kabul edilmiştir.'),
  ('Avrasya''da İlk Türk İzleri', 'Avrasya ve Türk Adı', 1, 'Avrasya, Asya ile Avrupa’nın büyük bölümünü kapsayan coğrafi alandır. Türkiye adı Bizans kaynaklarında ilk olarak VI. yüzyılda Orta Asya için kullanılmıştır. Türk adı, 552’de Kök Türk Devleti ile ilk kez resmî devlet adı olarak kullanılmıştır. Türk kelimesi Çin kaynaklarında miğfer, Kaşgarlı Mahmut’a göre olgunluk çağı anlamında açıklanmıştır.'),
  ('Avrasya''da İlk Türk İzleri', 'Orta Asya Kültür Merkezleri', 2, 'Anav, Afanesyevo, Andronova, Karasuk ve Tagar kültürleri Orta Asya’daki önemli kültür merkezleridir. Anav kültüründe ata ilk kez rastlanır; Afanesyevo ve Andronova kültürleri Ön Türklerle ilişkilendirilir. Karasuk kültürü demirin erken işlenmesiyle öne çıkmıştır. Tagar kültürü ise önceki Türk kültürlerinin gelişmiş devamı kabul edilir.'),
  ('Avrasya''da İlk Türk İzleri', 'Bozkır Coğrafyası ve Askerî Kültür', 3, 'Bozkır coğrafyası Türklerde hayvancılığa, yaylak-kışlak düzenine ve konar-göçer yaşama yol açmıştır. Eli silah tutan herkes asker sayıldığı için ordu-millet anlayışı gelişmiştir. Türk ordusunun temelini atlı okçular oluşturmuş; onlu sistem uygulanmıştır. Sahte geri çekilme ve pusudan oluşan Turan taktiği, Türklerin önemli savaş yöntemidir.'),
  ('Boylardan Devlete-I', 'Türklerde Sosyal Yapı', 1, 'Eski Türk toplumunda en küçük birlik aile yani oguştu. Aileler urugları, uruglar boyları, boylar budunları; budunlar ise devleti yani ili oluştururdu. Boy beyleri ekonomik ve siyasi güce sahip kişiler arasından seçilirdi. Mete Han, Türk boylarını ilk kez tek bayrak altında toplamıştır.'),
  ('Boylardan Devlete-I', 'Kut Anlayışı ve Devlet Teşkilatı', 2, 'Kut anlayışına göre yönetme yetkisi kağana Gök Tengri tarafından verilirdi. Kutun hanedan üyelerine de geçtiğine inanıldığı için bütün hanedan mensupları tahta aday olabilirdi. Kurultay, devlet işlerinin görüşüldüğü en yüksek danışma meclisiydi. Türklerde devlet yönetimini kolaylaştırmak amacıyla ikili teşkilat uygulanmış, ülke doğu ve batı olarak yönetilmiştir.'),
  ('Boylardan Devlete-II', 'Asya Hun ve I. Kök Türk Devletleri', 1, 'Asya Hun Devleti, tarihte bilinen ilk Türk devletidir ve Mete Han döneminde en güçlü zamanını yaşamıştır. Mete Han, Türk boylarını ilk kez siyasi birlik altında toplamış ve düzenli ilk Türk ordusunu kurmuştur. I. Kök Türk Devleti, Bumin Kağan tarafından 552’de kurulmuştur. Kök Türkler, Türk adını resmî devlet adı olarak kullanan ilk Türk devletidir.'),
  ('Boylardan Devlete-II', 'II. Kök Türk ve Uygur Devletleri', 2, 'II. Kök Türk Devleti, Kutluk Kağan tarafından Çin egemenliğine son verilerek kurulmuştur. Bilge Kağan, Kül Tigin ve Tonyukuk devletin güçlenmesinde etkili olmuştur. Uygurlar, II. Kök Türk Devleti’ne son vererek 744’te devlet kurmuştur. Maniheizmi kabul etmeleri Uygurları savaşçılıktan uzaklaştırmış, yerleşik hayata geçmelerini hızlandırmıştır.'),
  ('Boylardan Devlete-II', 'İlk Türk Devletlerinde Töre', 3, 'Töre; örf, âdet, gelenek ve ahlaki değerlerden oluşan sözlü hukuk kurallarıdır. Kağanın koyduğu kurallar ve kurultay kararları da törenin oluşumunda etkili olmuştur. Kağan dâhil herkes töreye uymak zorundaydı. Bu durum, Türklerde hukuk üstünlüğü anlayışının bulunduğunu gösterir.'),
  ('Kavimler Göçü', 'Kavimler Göçü ve Sonuçları', 1, 'Kavimler Göçü, Hunların baskısıyla Germen kavimlerinin 376 yılında Roma topraklarına yönelmesiyle başlayan büyük nüfus hareketidir. Bu gelişme Roma İmparatorluğu’nun Doğu ve Batı Roma olarak ayrılmasına, Avrupa Hun Devleti’nin kurulmasına ve Avrupa milletlerinin temellerinin atılmasına yol açtı. Avrupa’da feodalite güç kazandı, kilisenin etkisi arttı ve skolastik düşünce yaygınlaştı. Bazı tarihçilere göre Kavimler Göçü İlk Çağ’ın sonu, Orta Çağ’ın başlangıcı kabul edilir.'),
  ('Kavimler Göçü', 'Avrupa Hun Devleti', 2, 'Avrupa Hun Devleti, Balamir önderliğinde Avrupa’ya gelen Hunlar tarafından kuruldu. Uldız Han döneminde Doğu Roma ile iyi ilişkiler kurulması, Batı Roma üzerinde baskı oluşturulması siyaseti benimsendi. Devlet en güçlü dönemini Atilla zamanında yaşadı; Atilla Doğu Roma’yı Margus ve Anatolios Antlaşmaları ile vergiye bağladı, Batı Roma üzerine Galya Seferi’ni düzenledi. Avrupa’da Tanrı’nın Kırbacı olarak tanındı.'),
  ('Kavimler Göçü', 'Diğer Türk Boyları', 3, 'Avarlar, İstanbul’u kuşatan ilk Türk devleti olarak bilinir. Hazarlar Museviliği benimseyen tek Türk devleti olmuş, Karluklar Talas Savaşı’nda Abbasilere destek vermiştir. Peçenekler Malazgirt Savaşı’nda Büyük Selçuklu Devleti’nin yanında yer almıştır. Bu boylar, Türklerin farklı coğrafyalarda siyasi ve kültürel etkisini göstermesi açısından önemlidir.'),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'İslam Öncesi Arap Yarımadası', 1, 'İslamiyet öncesi Arap Yarımadası’nda siyasi birlik yoktu ve kabilecilik anlayışı hâkimdi. Putperestliğin yaygın olduğu bu dönem Cahiliye Dönemi olarak adlandırılır. Mekke önemli bir ticaret merkeziydi; Ukaz Panayırı ticari ve kültürel hayatın önemli merkezlerinden biriydi. Haram aylarda yapılan savaşlara Ficâr Savaşları denirdi.'),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'Dört Halife Dönemi', 2, 'Dört Halife Dönemi’nde halifeler seçimle iş başına geldiği için bu dönem Cumhuriyet Dönemi olarak da adlandırılır. Hz. Ebubekir döneminde Kur’an-ı Kerim kitap hâline getirildi; Hz. Ömer döneminde İran, Irak, Suriye ve Mısır fethedildi. Hz. Osman döneminde ilk İslam donanması kuruldu ve Kur’an çoğaltılarak eyaletlere gönderildi. Hz. Ali döneminde Cemel Vakası ve Sıffin Savaşı gibi ilk büyük iç karışıklıklar yaşandı.'),
  ('Emeviler', 'Emevi Siyaseti ve Mevali Politikası', 1, 'Emeviler döneminde Muaviye’nin oğlu Yezid’i veliaht göstermesiyle halifelik saltanata dönüştü. Kerbelâ Olayı, İslam dünyasında mezhep ayrılıklarının derinleşmesine neden oldu. Arap olmayan Müslümanlara ikinci sınıf muamele yapılmasına Mevali Politikası denir. Bu politika Türklerin İslamiyet’i kabulünü geciktirmiş ve Emevi yönetimine karşı tepkileri artırmıştır.'),
  ('Abbasi Devleti ve Türkler - Bilim', 'Abbasiler ve Mısır''da Kurulan Türk Devletleri', 1, 'Abbasiler, Emevileri yıkarak kuruldu ve başkentlerini Bağdat yaptı. Mevali anlayışını kaldırarak Türklerin orduda ve devlet yönetiminde daha etkin görev almasını sağladılar. Tolunoğulları Mısır’da kurulan ilk Müslüman Türk devletidir; İhşidiler, Eyyubiler ve Memlükler de Mısır-Suriye çevresinde etkili oldu. Eyyubiler, Selahaddin Eyyubi döneminde Hıttin Savaşı ile Kudüs’ü Haçlılardan geri aldı.'),
  ('Abbasi Devleti ve Türkler - Bilim', 'İslam Medeniyetinde Âlimler', 2, 'İslam medeniyetinde felsefe, tıp, matematik, astronomi ve coğrafya alanlarında önemli bilim insanları yetişmiştir. Farabi mantık ve felsefede İkinci Öğretmen olarak anılmıştır; İbn Sina El-Kanun fi’t-Tıbb adlı eseriyle tıp alanında öne çıkmıştır. Gazali dinî ilimler ve düşünce alanında, İbn Rüşd ise Aristo yorumlarıyla tanınmıştır. Bu âlimlerin eserleri hem İslam dünyasını hem Avrupa düşüncesini etkilemiştir.'),
  ('Türklerin İslamiyet''i Kabulü', 'Talas Savaşı ve İlk Türk İslam Devletleri', 1, '751 Talas Savaşı, Türklerle Müslüman Arapların yakınlaşmasını sağladı ve Türklerin İslamiyet’i benimseme sürecini hızlandırdı. Karahanlılar, Orta Asya’da kurulan ilk Müslüman Türk devletidir. Gazneliler ise Hindistan’a yaptıkları seferlerle İslamiyet’in yayılmasına katkı sağladı. Türklerin İslamiyet’i kabulünde Kök Tengri inancı ile İslamiyet arasındaki benzerlikler ve Abbasilerin hoşgörülü politikası etkili oldu.'),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Devlet Anlayışı ve Hükümdarlık Sembolleri', 1, 'Türkler İslamiyet’i kabul ettikten sonra eski devlet geleneklerini İslami unsurlarla birleştirdi. Kut anlayışı, Allah’ın hükümdara verdiği yönetme yetkisi şeklinde yorumlandı. Hutbe okutmak, para bastırmak, menşur almak, çetr ve tıraz kullanmak hükümdarlık sembolleri arasında yer aldı. Cihat anlayışı da devletlerin fetih politikalarında etkili oldu.'),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Türk-İslam Dünyasında İlk Eserler', 2, 'Kutadgu Bilig, Yusuf Has Hacip tarafından yazılmış ilk Türk-İslam siyasetnamesidir. Kaşgarlı Mahmut’un Divânü Lugati''t-Türk adlı eseri Türkçeyi Araplara öğretmek amacıyla hazırlanmıştır. Ahmet Yesevi’nin Divân-ı Hikmet’i tasavvuf düşüncesini yaymıştır. Atabetü’l-Hakayık ise Edip Ahmet Yükneki tarafından yazılmış ahlakî öğütler içeren bir eserdir.'),
  ('Büyük Selçuklu Devleti', 'Kuruluş ve Anadolu Akınları', 1, 'Büyük Selçuklu Devleti, 1040 Dandanakan Savaşı’ndan sonra resmen kuruldu. Tuğrul Bey, Abbasi halifesini Büveyhoğullarından kurtararak İslam dünyasında saygınlık kazandı. 1048 Pasinler Savaşı Bizans ile yapılan ilk savaş, 1071 Malazgirt Zaferi ise Anadolu’nun Türklere yurt olmasını sağlayan dönüm noktasıdır. Malazgirt’ten sonra Anadolu’da Türk beylikleri kurulmaya başladı.'),
  ('Büyük Selçuklu Devleti', 'Yönetim ve Kültür', 2, 'Büyük Selçuklu Devleti’nde mali işlerden Divan-ı İstifa, askerî işlerden Divan-ı Arz sorumluydu. Devlet yönetiminde vezirlik önemliydi; Nizamülmülk bu alanda öne çıkan devlet adamıdır. Nizamiye Medreseleri eğitim ve bilim hayatını geliştirmek, Bâtınilik hareketine karşı Sünni düşünceyi güçlendirmek amacıyla açıldı. Selçuklu teşkilatı, sonraki Türk-İslam devletlerine örnek oldu.'),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Anadolu''ya İlk Akınlar ve Türkiye Adı', 1, 'Türkler Anadolu’ya ilk kez Avrupa Hunları, daha sonra Sabarlar döneminde akınlar düzenledi. 1071 Malazgirt Zaferi ile Anadolu’nun yurt edinilme süreci başladı. Bizans’ın Anadolu’daki gücü zayıfladı ve Türk beyliklerinin kurulması kolaylaştı. Türkiye adı XII. yüzyıldan itibaren Anadolu için kullanılmaya başlanmıştır.'),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Oğuz Göçlerinin Nedenleri', 2, 'Oğuzların Anadolu’ya yönelmesinde verimli topraklar, uygun iklim, hayvancılığa elverişli alanlar ve ticaret yolları etkili oldu. Bizans’ın siyasi karışıklık içinde olması Türk ilerleyişini kolaylaştırdı. Gaza ve cihat anlayışı da fetihleri teşvik etti. Oğuz göçleri Anadolu’nun Türkleşme ve İslamlaşma sürecini hızlandırdı.'),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Anadolu''da Kurulan İlk Türk Beylikleri', 1, 'Malazgirt Zaferi’nden sonra Anadolu’da Saltuklular, Danişmentliler, Mengücekliler, Artuklular ve Çaka Beyliği kuruldu. Saltuklular Anadolu’daki ilk Türk beyliği kabul edilir. Danişmentliler Yağıbasan Medresesi’ni kurarak eğitim alanında öne çıktı. Çaka Bey, ilk Türk donanmasını kurarak denizcilik faaliyetlerini başlattı.'),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Türkiye Selçuklu Devleti ve Miryokefalon', 2, 'Türkiye Selçuklu Devleti, Kutalmışoğlu Süleyman Şah tarafından İznik merkezli kuruldu. Haçlı Seferleri nedeniyle başkent Konya’ya taşındı. 1176 Miryokefalon Savaşı ile Bizans’ın Anadolu’yu geri alma ümidi büyük ölçüde sona erdi. Bu zafer, Anadolu’nun kesin Türk yurdu hâline geldiğinin önemli göstergesi kabul edilir.'),
  ('Hilal ve Haç Mücadelesi', 'Haçlı Seferleri ve Nedenleri', 1, 'Haçlı Seferleri, Hristiyan Avrupa’nın Kudüs ve çevresindeki kutsal yerleri ele geçirmek amacıyla düzenlediği seferlerdir. Seferlerin dinî nedenlerinin yanında ticaret yollarına hâkim olma, toprak kazanma ve Doğu’nun zenginliklerine ulaşma isteği de etkili olmuştur. I. Haçlı Seferi sonunda Urfa Kontluğu, Antakya Prensliği, Kudüs Krallığı ve Trablus Kontluğu kuruldu. Papa II. Urban’ın çağrısı seferlerin başlamasında etkili oldu.'),
  ('Hilal ve Haç Mücadelesi', 'Sonraki Seferler ve Genel Sonuçlar', 2, '1187 Hıttin Savaşı’nda Selahaddin Eyyubi Kudüs’ü Haçlılardan geri aldı; bunun üzerine III. Haçlı Seferi düzenlendi. IV. Haçlı Seferi’nde Haçlılar İstanbul’u işgal ederek Latin İmparatorluğu’nu kurdu. Haçlı Seferleri sonunda Avrupa’da derebeylik zayıfladı, merkezî krallıklar ve ticaret güç kazandı. Doğu-Batı etkileşimi arttı; pusula, barut ve kâğıt gibi gelişmeler Avrupa’da yaygınlaştı.'),
  ('Moğol İstilası ve Anadolu', 'Yassıçemen, Baba İshak ve Kösedağ Savaşı', 1, '1230 Yassıçemen Savaşı sonunda Harzemşahlar yıkıldı ve Türkiye Selçuklu Devleti Moğollarla komşu oldu. 1240 Baba İshak İsyanı, Türkiye Selçuklu Devleti’ni içten zayıflattı. 1243 Kösedağ Savaşı’nda Moğollara yenilen Türkiye Selçuklu Devleti Moğol egemenliğine girdi. Bu süreçte Anadolu’da siyasi birlik bozuldu ve II. Dönem Türk Beylikleri ortaya çıktı.'),
  ('Osmanlı Beyliği''nin Kuruluşu', 'Osman ve Orhan Gazi Dönemi', 1, 'Osmanlı Beyliği, Bizans sınırındaki Söğüt ve Domaniç çevresinde Kayı Boyu tarafından kuruldu. 1302 Koyunhisar Savaşı, Osmanlı hanedanının siyasi ve kurumsal olarak devletleşmesinin başlangıcı kabul edilir. Orhan Gazi döneminde Bursa fethedilerek merkez yapıldı; yaya ve müsellem adı verilen ilk düzenli birlikler kuruldu. 1329 Maltepe Savaşı ile Bizans’ın Anadolu’daki gücü zayıfladı, Kocaeli çevresi Osmanlı hâkimiyetine girdi.'),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'Rumeli''ye Geçiş ve Çimpe Kalesi', 1, 'Karesioğulları’nın Osmanlı topraklarına katılmasıyla Osmanlı Devleti donanma gücü kazandı. Orhan Bey, Bizans’taki taht mücadelesinde Kantakuzen’e yardım etti. Bu yardımın karşılığında 1353’te Çimpe Kalesi Osmanlılara verildi. Çimpe Kalesi, Osmanlıların Rumeli’de elde ettiği ilk toprak ve Balkan fetihlerinin başlangıcı oldu.'),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'İskân ve İstimâlet Politikası', 2, 'Osmanlı Devleti, fethedilen yerlere Türkmen nüfus yerleştirerek iskân politikası uyguladı. Bu politika Rumeli’nin Türkleşmesini, İslamlaşmasını ve bölgede kalıcı egemenlik kurulmasını sağladı. İstimâlet politikasıyla gayrimüslim halka din, dil ve yaşam özgürlüğü tanındı. Böylece halkın Osmanlı yönetimine uyumu kolaylaştı ve isyanlar azaltılmaya çalışıldı.'),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Osmanlı''nın Beylikleri Katma Politikası', 1, 'Osmanlı Devleti Anadolu Türk siyasi birliğini evlilik, satın alma, savaş ve diplomasi gibi yöntemlerle sağlamaya çalıştı. Osmanlı topraklarına katılan ilk Anadolu beyliği Karesioğulları’dır. Karesioğulları’nın katılmasıyla Osmanlı hem donanma kazandı hem Rumeli fetihleri için önemli bir avantaj elde etti. Beyliklerin Osmanlı yönetiminde birleşmesi merkezî otoriteyi güçlendirdi.'),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Ankara Savaşı ve Fetret Devri', 2, '1402 Ankara Savaşı’nda Osmanlı Devleti Timur’a yenildi ve Yıldırım Bayezid esir düştü. Savaşın ardından Anadolu Türk siyasi birliği bozuldu, birçok beylik yeniden kuruldu ve Fetret Devri başladı. Yaklaşık 11 yıl süren taht mücadeleleri, Çelebi Mehmet’in tahta çıkmasıyla sona erdi. Çelebi Mehmet, devleti yeniden toparladığı için Osmanlı’nın ikinci kurucusu kabul edilir.'),
  ('Savaşçılar ve Askerler', 'Tımar Sistemi ve Tımarlı Sipahiler', 1, 'Tımar sistemi, devlete ait toprakların gelirlerini bazı asker ve görevlilere hizmet karşılığında bırakma uygulamasıdır. Tımarlı sipahiler sefer zamanında orduya katılır, taşrada güvenliği sağlar ve cebelü adı verilen atlı askerler yetiştirirdi. Sistem tarımsal üretimin devamını ve vergilerin düzenli toplanmasını destekledi. Osmanlı Devleti bu sayede hazineden doğrudan para harcamadan güçlü eyalet askerleri yetiştirdi.'),
  ('Savaşçılar ve Askerler', 'Kapıkulu Ocakları ve Devşirme', 2, 'Kapıkulu Ocakları, Osmanlı Devleti’nin maaşlı ve sürekli merkez ordusunu oluştururdu. Yeniçeriler bu ordunun en önemli piyade gücüydü; üç ayda bir ulufe adı verilen maaş alırlardı. Pençik sistemi savaş esirlerinin beşte birinin devlet hizmetine alınmasına dayanırdı. Devşirme sistemiyle Rumeli’deki Hristiyan ailelerden alınan çocuklar eğitilerek askerî ve idarî görevlerde yetiştirilirdi.'),
  ('Sosyal ve Kültürel Faaliyetler', 'Osmanlı''da Yönetici Sınıflar (Askerî)', 1, 'Osmanlı toplumunda yöneten kesime askerî, vergi veren halka ise reaya denirdi. Askerî sınıf seyfiye, ilmiye ve kalemiye olarak ayrılırdı. Seyfiye askerî ve idarî işlerle; ilmiye eğitim, din ve adaletle; kalemiye ise yazışma ve mali işlerle ilgilenirdi. Kadı, kazasker ve şeyhülislam ilmiye; defterdar ve nişancı kalemiye sınıfında yer alırdı.'),
  ('Sosyal ve Kültürel Faaliyetler', 'Mutasavvıflar ve Bilim İnsanları', 2, 'Ahilik teşkilatının kurucusu Ahi Evran’dır; teşkilat esnaf arasında dayanışmayı, üretim kalitesini ve meslek ahlakını geliştirmiştir. Akşemseddin, hastalıkların gözle görülmeyen canlılarla bulaştığını belirten fikirleriyle tanınır. Ali Kuşçu, astronomi ve matematik alanındaki çalışmalarıyla öne çıkmıştır. Bu isimler Osmanlı toplumunda bilim, tasavvuf ve meslek hayatının gelişmesine katkı sağlamıştır.'),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Nedenleri ve Hazırlıklar', 1, 'İstanbul’un fethi, Osmanlı toprak bütünlüğünü sağlamak ve Bizans’ın Osmanlı aleyhindeki faaliyetlerine son vermek amacıyla gerçekleştirildi. Fatih Sultan Mehmet, Rumeli Hisarı’nı yaptırdı; Şahi toplarını döktürdü ve güçlü bir donanma hazırladı. Bizans’ın denizden yardım almasını engellemek için Boğaz denetim altına alındı. Fetih 29 Mayıs 1453’te gerçekleşti.'),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Dünya Tarihine Etkisi', 2, 'İstanbul’un fethiyle Bizans Devleti sona erdi; geleneksel kabulde Orta Çağ kapanıp Yeni Çağ başladı. Büyük topların surları yıkabileceğinin anlaşılması Avrupa’da derebeyliklerin zayıflamasını hızlandırdı. Bizanslı bazı bilim insanlarının İtalya’ya gitmesi Rönesans’ın gelişimine katkı sağladı. İstanbul, Osmanlı Devleti’nin siyasi ve ekonomik merkezi hâline geldi.'),
  ('İslam Dünyasında Birliği Sağlama', 'Safevi ve Memluk Mücadelesi (Yavuz Dönemi)', 1, 'Yavuz Sultan Selim, 1514 Çaldıran Savaşı ile Safevi tehlikesini büyük ölçüde azalttı ve doğu sınırını güvence altına aldı. 1516 Mercidabık ve 1517 Ridaniye savaşlarıyla Memlük Devleti yıkıldı. Suriye, Filistin, Mısır ve Hicaz Osmanlı topraklarına katıldı; Baharat Yolu’nun önemli kısmı Osmanlı denetimine geçti. Halifeliğin Osmanlılara geçmesiyle Osmanlı Devleti İslam dünyasında daha güçlü bir konum kazandı.'),
  ('Dünyanın Muhteşem Gücü Osmanlı', 'Kanuni Sultan Süleyman Dönemi', 1, 'Kanuni Sultan Süleyman döneminde Osmanlı Devleti siyasi, askerî ve hukuk alanlarında en güçlü dönemlerinden birini yaşadı. Belgrad ve Rodos fethedildi; 1526 Mohaç Meydan Muharebesi ile Macaristan Krallığı sona erdirildi. 1533 İstanbul Antlaşması, Osmanlı’nın Avusturya karşısındaki siyasi üstünlüğünü gösterdi. Kanuni’nin son seferi Zigetvar Seferi oldu.'),
  ('Stratejik Siyaset ve Dünya Gücü', 'Kapitülasyonlar', 1, 'Kapitülasyonlar, Osmanlı Devleti’nin yabancı devletlere verdiği ticari ve hukuki ayrıcalıklardır. Kanuni Sultan Süleyman, Fransa’ya kapitülasyon vererek Avrupa’daki Habsburg baskısını dengelemeyi ve Haçlı birliğini parçalamayı amaçladı. Başlangıçta geçici olan kapitülasyonlar 1740’ta sürekli hâle geldi. Zamanla yabancı devletlerin ekonomik üstünlük kurmasına yol açarak Osmanlı ekonomisini olumsuz etkiledi.'),
  ('Stratejik Siyaset ve Dünya Gücü', 'Hint Deniz Seferleri', 2, 'Osmanlı Devleti, Portekiz’in Baharat Yolu ticaretini engellemesi ve Müslüman gemilerine saldırması üzerine Hint Deniz Seferleri düzenledi. Amaç Baharat Yolu’nu canlandırmak, Portekiz üstünlüğünü kırmak ve bölgedeki Müslüman devletlere yardım etmekti. Seferler sonucunda Kızıldeniz ve Basra Körfezi’nin güvenliği güçlendirildi. Ancak Osmanlı gemilerinin açık denizlere yeterince dayanıklı olmaması ve bölge halkının tam destek vermemesi nedeniyle kesin başarı sağlanamadı.'),
  ('Saray ve Şehir Kültürü', 'Saray Teşkilatı', 1, 'Osmanlı sarayı Birun, Enderun ve Harem olmak üzere üç bölümden oluşurdu. Birun devlet hizmetlerinin yürütüldüğü dış saray bölümüdür. Enderun, devşirme kökenli öğrencilerin yetiştirildiği ve devlet adamı yetiştiren eğitim kurumudur. Harem ise padişahın ailesiyle birlikte yaşadığı özel bölümdür.'),
  ('Saray ve Şehir Kültürü', 'Divan-ı Hümayun', 2, 'Divan-ı Hümayun, devlet işlerinin görüşüldüğü en önemli yönetim organıdır. Fatih Sultan Mehmet döneminden itibaren divana sadrazam başkanlık etmeye başlamıştır. Defterdar mali işlerden, kazasker adalet ve eğitimden, nişancı ise devlet yazışmaları ile tapu işlerinden sorumluydu. Divan, merkezî yönetimin karar alma mekanizmasını oluştururdu.'),
  ('Saray ve Şehir Kültürü', 'Gelenekler Işığında Devlet İdaresi', 3, 'Fatih Sultan Mehmet, merkezi otoriteyi güçlendirmek için kanunnameler hazırlattı ve kardeş katli uygulamasını hukuki zemine oturttu. I. Ahmet döneminde Ekber ve Erşed Sistemi kabul edilerek hanedanın en yaşlı üyesinin tahta geçmesi benimsendi. Şehzadelerin sancağa çıkma usulü kaldırıldı ve kafes usulü yaygınlaştı. Bu değişiklikler taht kavgalarını azaltmayı amaçladı.'),
  ('Millet Sistemi', 'Osmanlı Millet Sistemi', 1, 'Osmanlı Devleti toplumunu din ve mezhep esasına göre millet sistemiyle yönetmiştir. Gayrimüslimler kendi dinî, hukuki ve eğitim işlerinde serbest bırakılmıştır. Bunun karşılığında devlete cizye vergisi ödemişlerdir. Millet sistemi, farklı toplulukların uzun süre Osmanlı yönetimi altında birlikte yaşamasını sağlamıştır.'),
  ('Toprak Sistemi ve Lonca', 'Osmanlı Toprak Sistemi', 1, 'Osmanlı toprakları miri, mülk ve vakıf arazileri olarak üçe ayrılmıştır. Miri arazilerin mülkiyeti devlete aittir; bu toprakların gelirleri has, zeamet ve tımar olarak dağıtılmıştır. Tımar sistemi hem devlet gelirlerinin düzenli toplanmasını hem de asker yetiştirilmesini sağlamıştır. Toprağın boş kalmaması ve üretimin sürmesi devlet tarafından önemsenmiştir.'),
  ('Toprak Sistemi ve Lonca', 'Lonca Teşkilatı ve Narh', 2, 'Lonca teşkilatı, esnaf ve zanaatkârlar arasında meslek düzenini, üretim kalitesini ve dayanışmayı sağlamıştır. Çıraklık, kalfalık ve ustalık sistemiyle nitelikli eleman yetiştirilmiştir. Devlet, temel ihtiyaç maddelerinin fiyatlarını narh uygulamasıyla denetlemiştir. Gedik sistemi ise bir mesleği yapma hakkını düzenlemiştir.'),
  ('Uzun Savaşlardan Diplomasiye', 'Zitvatorok ve Bucaş Antlaşmaları', 1, '1606 Zitvatorok Antlaşması ile Osmanlı Devleti’nin Avusturya üzerindeki siyasi üstünlüğü sona erdi ve Avusturya hükümdarı Osmanlı padişahına denk kabul edildi. 1672 Bucaş Antlaşması ile Podolya Osmanlı topraklarına katıldı. Bucaş Antlaşması, Osmanlı Devleti’nin batıda ulaştığı en geniş sınırları göstermesi bakımından önemlidir. Bu dönem Osmanlı’nın uzun savaşlar yerine diplomasiye daha fazla yönelmeye başladığı süreçtir.'),
  ('Uzun Savaşlardan Diplomasiye', 'Karlofça ve 1700 İstanbul Antlaşması', 2, '1699 Karlofça Antlaşması ile Osmanlı Devleti ilk kez geniş çaplı toprak kaybetti; Macaristan ve Transilvanya Avusturya’ya, Podolya Lehistan’a, Mora ise Venedik’e bırakıldı. 1700 İstanbul Antlaşması ile Azak Kalesi Rusya’ya verildi. Bu antlaşmalar Osmanlı Devleti’nin Avrupa karşısında savunmaya çekildiğini gösterir. Osmanlı Devleti kaybettiği toprakları geri alma siyasetine yönelmiştir.'),
  ('Okyanusların Önem Kazanması', 'Coğrafi Keşifler ve Kadırgadan Kalyona Geçiş', 1, 'Coğrafi Keşifler sonrasında İpek ve Baharat yolları eski önemini kaybetti, ticaret Atlas Okyanusu kıyılarına yöneldi. Bu durum Osmanlı Devleti’nin gümrük ve liman gelirlerini olumsuz etkiledi. Deniz savaşlarının okyanuslara taşınmasıyla kürekli kadırgaların yerini daha güçlü, yelkenli ve çok toplu kalyonlar almaya başladı. Osmanlı Devleti de deniz gücünü korumak için kalyon kullanımına yöneldi.'),
  ('Fetihlerden Savunmaya', 'Prut ve Pasarofça Antlaşmaları', 1, '1711 Prut Antlaşması, Osmanlı Devleti ile Rusya arasında imzalandı ve Osmanlı Devleti Rusya karşısında önemli bir başarı kazandı. Ancak 1718 Pasarofça Antlaşması ile Belgrad ve çevresi Avusturya’ya bırakıldı. Pasarofça’dan sonra Osmanlı Devleti Avrupa karşısında fetih siyasetini büyük ölçüde bırakıp savunma ve ıslahat politikalarına yöneldi.'),
  ('Fetihlerden Savunmaya', 'Belgrad ve Küçük Kaynarca Antlaşmaları', 2, '1739 Belgrad Antlaşması ile Belgrad ve Semendire yeniden Osmanlı topraklarına katıldı. 1774 Küçük Kaynarca Antlaşması, Osmanlı Devleti’nin Rusya karşısında imzaladığı en ağır antlaşmalardan biridir. Kırım bağımsız hâle getirildi, Rusya Karadeniz’de güç kazandı ve Osmanlı Devleti’nin iç işlerine karışma fırsatı elde etti.'),
  ('Avrupa''da Değişim Çağı', 'Rönesans, Reform ve Vestfalya', 1, 'Rönesans, ilk olarak İtalya’da başlamış; bilim, sanat ve özgür düşüncenin gelişmesini sağlamıştır. Reform hareketleri Almanya’da başlamış ve Katolik Kilisesi’nin otoritesini zayıflatmıştır. 1648 Vestfalya Antlaşması Avrupa’daki din savaşlarını sona erdirmiş, modern devletler hukukunun ve ulus devlet anlayışının gelişmesine zemin hazırlamıştır.'),
  ('Avrupa''da Değişim Çağı', 'Bilim Devrimi ve Aydınlanma', 2, 'Bilim Devrimi’nde Kopernik, Kepler, Galileo ve Newton evren, hareket ve fizik alanında önemli çalışmalar yapmıştır. Aydınlanma Çağı’nda akıl, bilim, özgürlük ve eşitlik düşünceleri öne çıkmıştır. Rousseau, Montesquieu ve Voltaire gibi düşünürlerin fikirleri Sanayi Devrimi ve Fransız İhtilali üzerinde etkili olmuştur.'),
  ('Osmanlı Devleti''nde Değişim', 'Ekonomik Sarsıntı ve İltizam Sistemi', 1, 'Coğrafi Keşifler ve uzun savaşlar Osmanlı ekonomisini olumsuz etkiledi. Devlet, gelirlerini artırmak için vergi toplama hakkını açık artırmayla mültezimlere bıraktığı iltizam sistemini yaygınlaştırdı. Daha sonra malikâne sistemiyle bazı vergi kaynakları ömür boyu işletilmek üzere verildi. Bu uygulamalar taşrada ayanların güç kazanmasına yol açtı.'),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 1, 'Celâli İsyanları; ağır vergiler, ekonomik sıkıntılar, savaşlar ve devlet otoritesinin zayıflaması nedeniyle Anadolu’da çıktı. Yeniçeri İsyanları ise merkezî otoriteyi zayıflattı ve II. Osman’ın öldürülmesi gibi önemli sonuçlar doğurdu. Devleti düzeltmek için layihalar hazırlanmış, ancak kalıcı çözüm üretmekte zorlanılmıştır.'),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 2, 'Ekber ve Erşed Sistemi ile hanedanın en yaşlı ve olgun üyesinin tahta geçmesi kabul edildi; böylece taht kavgalarının azaltılması amaçlandı. 1718 Pasarofça Antlaşması ile başlayan Lale Devri’nde Avrupa’yı tanıma, kültürel gelişme ve yenilik hareketleri öne çıktı. İlk Türk matbaası kuruldu, geçici elçilikler açıldı ve Tulumbacılar Ocağı oluşturuldu. Lale Devri, 1730 Patrona Halil İsyanı ile sona erdi.'),
  ('İhtilaller Çağı', '1789 Fransız İhtilali', 1, '1789 Fransız İhtilali, Fransa’da mutlak monarşiyi yıkarak cumhuriyetin ilan edilmesine yol açtı. Eşitlik, özgürlük, demokrasi, millî egemenlik ve milliyetçilik düşünceleri Avrupa’ya yayıldı. Milliyetçilik özellikle çok uluslu imparatorluklarda azınlık isyanlarını ve parçalanmaları hızlandırdı. Osmanlı Devleti’nde XIX. yüzyıldaki Sırp ve Yunan isyanlarında bu düşüncenin etkisi görüldü.'),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Zorunlu Askerlik Sistemi', 1, 'Fransız İhtilali sonrasında gelişen milliyetçilik ve vatandaşlık anlayışı, devletlerin geniş ve düzenli ordular kurmasına yol açtı. Zorunlu askerlik sistemi, halkın devletle bütünleşmesini ve modern orduların kurulmasını amaçladı. Ordu, devletlerin hem savunma gücü hem de toplumu dönüştürme aracı olarak görülmeye başladı.'),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Nizam-ı Cedit Ordusu', 2, 'III. Selim döneminde Batı tarzında eğitim veren Nizam-ı Cedit ordusu kuruldu. Ordunun ihtiyaçlarını karşılamak için İrad-ı Cedit hazinesi oluşturuldu. Nizam-ı Cedit uygulamaları yeniçeriler ve bazı çevrelerin tepkisiyle karşılaştı. 1807 Kabakçı Mustafa İsyanı sonrasında ordu dağıtıldı ve III. Selim tahttan indirildi.'),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Vakay-ı Hayriye ve Yeni Ordu', 3, 'II. Mahmut, 1826’da Yeniçeri Ocağı’nı kaldırdı; bu olay Vakay-ı Hayriye olarak adlandırıldı. Yeniçeriliğin kaldırılmasıyla askerî yeniliklerin önündeki önemli engellerden biri ortadan kalktı. Yerine Batı tarzında Asâkir-i Mansûre-i Muhammediye ordusu kuruldu. Bu gelişme Osmanlı’da modern orduya geçişin en önemli adımlarındandır.'),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Ulaşım ve Haberleşme', 1, 'XIX. yüzyılda demir yolu ve telgraf hatları Osmanlı Devleti’nde ulaşımı ve haberleşmeyi hızlandırdı. İlk demir yolu İzmir-Aydın arasında açıldı; II. Abdülhamid döneminde Hicaz Demir Yolu yapıldı. İlk telgraf hattı Kırım Savaşı sırasında kuruldu. Telgraf, merkezî yönetimin taşra üzerindeki denetimini güçlendirdi.'),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Modern Eğitim Kurumları', 2, 'Osmanlı Devleti modern subay ve memur yetiştirmek için yeni okullar açtı. Hendesehane modern askerî eğitim veren ilk okul kabul edilir. Mühendishane-i Bahr-i Hümâyun denizcilik, Mühendishane-i Berr-i Hümâyun kara ordusu için eğitim verdi. Mekteb-i Mülkiye ise sivil yönetici yetiştirmek amacıyla açıldı.'),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Sosyal Devlet ve Simgeler', 3, 'II. Abdülhamid döneminde sosyal yardım ve güvenlik kurumları yaygınlaştı. Darülaceze kimsesiz ve muhtaç kişiler için, Tekaüd Sandığı memurların emeklilik ihtiyaçları için kuruldu. Darülhayr-ı Ali ve Himaye-i Etfal Cemiyeti çocuklara yönelik sosyal yardım faaliyetlerinde bulundu. Ay-yıldızlı al sancak da bu dönemde resmî devlet simgesi olarak benimsendi.'),
  ('Osmanlı Devleti''ne Yönelik Tehditler-I', 'Şark Meselesi ve Projeler', 1, 'Şark Meselesi, Avrupa devletlerinin Osmanlı Devleti’ni parçalama ve Türkleri Avrupa’dan çıkarma düşüncesidir. Kavram, 1815 Viyana Kongresi’nde Avrupa diplomasisinin önemli konularından biri hâline geldi. Rusya, Osmanlı toprakları üzerinde etkisini artırmak amacıyla Grek Projesi ve Panslavizm gibi politikalar izledi. Bu politikalar Osmanlı Devleti’nin toprak bütünlüğünü tehdit etti.'),
  ('Osmanlı Devleti''ne Yönelik Tehditler-I', 'Sırp ve Yunan İsyanları', 2, 'Fransız İhtilali’nin yaydığı milliyetçilik düşüncesi Osmanlı Devleti’ndeki azınlık isyanlarını etkiledi. Sırplar, 1804’te Kara Yorgi önderliğinde isyan eden ilk Osmanlı topluluğu oldu. Yunan İsyanı 1821’de Mora’da başladı; Navarin Baskını’nda Osmanlı donanması yakıldı. 1829 Edirne Antlaşması ile Yunanistan bağımsızlığını kazandı.'),
  ('Osmanlı Devleti''ne Yönelik Tehditler-I', 'Kırım Savaşı ve 93 Harbi', 3, 'Kırım Savaşı’nda Osmanlı Devleti, İngiltere ve Fransa’nın desteğiyle Rusya’ya karşı savaştı. Osmanlı ilk dış borcunu bu savaş sırasında aldı; 1856 Paris Antlaşması ile Avrupa devletler hukukundan yararlanan devletler arasında kabul edildi. 1877-1878 Osmanlı-Rus Savaşı yani 93 Harbi sonrasında Berlin Antlaşması imzalandı. Bu antlaşmayla Sırbistan, Karadağ ve Romanya bağımsız oldu; Ermeni meselesi uluslararası boyut kazandı.'),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Sened-i İttifak ve Tanzimat Fermanı', 1, 'Sened-i İttifak, 1808’de devlet görevlileri ile ayanlar arasında imzalandı. Padişahın yetkilerini hukuken sınırlandırması bakımından Osmanlı demokratikleşme hareketlerinin ilk adımlarından biri kabul edilir. Tanzimat Fermanı ise 1839’da ilan edilerek can, mal ve namus güvenliğini güvence altına aldı. Bu fermanla hukuk devleti ve anayasal yönetime geçiş anlayışı güç kazandı.'),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Islahat Fermanı', 2, '1856 Islahat Fermanı, özellikle gayrimüslimlere yeni haklar tanımak amacıyla ilan edildi. Osmanlı Devleti, Avrupa devletlerinin azınlıklar üzerinden iç işlerine karışmasını azaltmayı hedefledi. Gayrimüslimlere devlet memurluğu, okul açma ve mahkemelerde eşitlik gibi alanlarda haklar verildi. Ancak ferman Avrupa devletlerinin Osmanlı iç işlerine müdahalesini tamamen engelleyemedi.'),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Kanun-ı Esasi ve Siyasi Partiler', 3, '1876 Kanun-ı Esasi, Türk tarihinin ilk yazılı anayasasıdır ve I. Meşrutiyet Dönemi’ni başlatmıştır. Meclis-i Umumi; Ayan Meclisi ve Mebusan Meclisi olmak üzere iki bölümden oluştu, seçimlerde iki dereceli sistem uygulandı. 1908’de II. Meşrutiyet ilan edilerek anayasa yeniden yürürlüğe kondu. Bu dönemde siyasi partiler kurulmuş ve Osmanlı tarihinde çok partili hayata geçilmiştir.'),
  ('Osmanlı Devleti''nde Darbeler', '1876 Darbesi ve 31 Mart Vakası', 1, '1876’da Sultan Abdülaziz, devlet adamlarının gerçekleştirdiği darbeyle tahttan indirildi. Bu olay, Osmanlı tarihinde bir padişahın devlet içindeki siyasi aktörler tarafından görevden uzaklaştırılmasının ilk önemli örneğidir. 1909’daki 31 Mart Vakası, II. Meşrutiyet yönetimine karşı çıkan ayaklanmadır. Hareket Ordusu isyanı bastırmış, II. Abdülhamid tahttan indirilmiştir.'),
  ('Osmanlı Devleti''nde Darbeler', 'Babıâli Baskını', 2, '1913 Babıâli Baskını, İttihat ve Terakki Cemiyetinin hükûmeti zor kullanarak devirmesidir. Baskın sonrasında Kâmil Paşa Hükûmeti görevden uzaklaştırıldı. İttihat ve Terakki yönetimde belirleyici güç hâline geldi. Osmanlı Devleti I. Dünya Savaşı’na bu siyasi ortam içinde girdi.'),
  ('Osmanlı Devleti''ne Yönelik Tehditler-II', 'Mehmet Ali Paşa ve Boğazlar', 1, 'Mısır Valisi Kavalalı Mehmet Ali Paşa’nın isyanı Osmanlı Devleti’ni zor durumda bıraktı. Osmanlı, Rusya’dan destek almak için 1833 Hünkâr İskelesi Antlaşması’nı imzaladı. Avrupa devletleri Rusya’nın Boğazlar üzerindeki etkisinden rahatsız oldu. 1841 Londra Boğazlar Sözleşmesi ile Boğazlar ilk kez uluslararası bir statü kazandı.'),
  ('Osmanlı Devleti''ne Yönelik Tehditler-II', 'Reval Görüşmesi ve Bloklaşmalar', 2, '1908 Reval Görüşmesi, İngiltere ve Rusya arasında gerçekleşti ve Osmanlı Devleti üzerindeki baskıyı artırdı. Avrupa’da Almanya, Avusturya-Macaristan ve İtalya Üçlü İttifak’ı oluşturdu. İngiltere, Fransa ve Rusya ise Üçlü İtilaf Devletleri olarak birleşti. Bu bloklaşma, I. Dünya Savaşı’na giden süreci hızlandırdı.'),
  ('Osmanlıda Sanayileşme Çabaları', 'Balta Limanı Antlaşması (1838)', 1, 'Balta Limanı Antlaşması 1838’de İngiltere ile imzalandı. Antlaşma ile iç ve dış ticaretteki sınırlamalar kaldırıldı, yabancı tüccarlara geniş ayrıcalıklar tanındı. Yerli üretici Avrupa mallarıyla rekabet edemedi ve Osmanlı ekonomisi açık pazar hâline geldi. Bu gelişme Osmanlı sanayisinin zayıflamasını hızlandırdı.'),
  ('Osmanlıda Sanayileşme Çabaları', 'Dış Borçlar ve Düyûn-ı Umûmiye', 2, 'Osmanlı Devleti ilk dış borcu 1854’te Kırım Savaşı sırasında aldı. Borçların üretime ve yatırıma dönüşmemesi, bütçe açıklarının büyümesine yol açtı. Borçlar ödenemeyince 1881 Muharrem Kararnamesi ile Düyûn-ı Umûmiye İdaresi kuruldu. Bu kurum bazı Osmanlı gelirlerini alacaklı devletler adına denetleyerek mali bağımsızlığı zedeledi.'),
  ('Osmanlıda Sanayileşme Çabaları', 'Millî İktisat Politikası', 3, 'İttihat ve Terakki yönetimi, I. Dünya Savaşı yıllarında yerli üretimi ve millî sermayeyi güçlendirmeyi amaçladı. Kapitülasyonlar tek taraflı kaldırıldı, koruyucu gümrük uygulamalarına yönelindi. Millî bankalar kurulması ve Teşvik-i Sanayi Kanunu bu politikanın önemli adımlarıdır. Amaç ekonomide yabancı etkisini azaltıp yerli girişimciyi desteklemekti.'),
  ('XIX ve XX. Yüzyılda Osmanlı Nüfusu', 'Kafkas Göçleri', 1, 'Kırım’ın kaybı ve Rusya’nın Kafkasya’daki baskıları sonucu çok sayıda Müslüman Türk Anadolu’ya göç etti. Bu göçler Anadolu’daki Türk-Müslüman nüfus oranını artırdı. Göçmenlerin yerleştirilmesi konut, üretim ve altyapı sorunlarını da beraberinde getirdi. Göçler, Anadolu’nun demografik yapısında kalıcı değişikliklere yol açtı.'),
  ('XIX ve XX. Yüzyılda Osmanlı Nüfusu', 'Metropoller ve Kamuoyu', 2, 'Şehir merkezlerine yapılan plansız göçler, konut ve altyapı sorunlarını artırdı. Salgın hastalıklarla mücadele için karantina uygulamaları ve sağlık kurumları geliştirildi. Takvim-i Vekayi, 1831’de yayımlanan ilk resmî Osmanlı gazetesi oldu. Gazetelerin yaygınlaşması kamuoyunun oluşmasına katkı sağladı.'),
  ('Mustafa Kemal''in Lider Olarak Yetişmesi', 'Eğitim Hayatı ve Etkilendiği Şehirler', 1, 'Mustafa Kemal eğitim hayatına Selanik’te başladı; Manastır ve İstanbul’da devam etti. İlk görev yeri olan Şam’da Vatan ve Hürriyet Cemiyetini kurdu. Sofya’da askerî ataşe olarak görev yapması, Avrupa diplomasisini ve Balkan siyasetini yakından tanımasını sağladı. Eğitim gördüğü ve görev yaptığı şehirler, onun askerî ve siyasi kişiliğinin gelişiminde etkili oldu.'),
  ('Mustafa Kemal''in Lider Olarak Yetişmesi', 'Fikir Hayatını Etkileyenler', 2, 'Namık Kemal’in vatan ve hürriyet düşünceleri, Mustafa Kemal’in fikrî gelişiminde etkili oldu. Ziya Gökalp ve Mehmet Emin Yurdakul, milliyetçilik anlayışını; Tevfik Fikret ise yenilikçi düşüncelerini etkiledi. Rousseau’nun halk egemenliği ve cumhuriyetçilik fikirlerinden yararlandı. Bu düşünceler, onun millî egemenlik ve çağdaşlaşma anlayışının temelini oluşturdu.'),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Fikir Akımları', 1, 'Osmanlı Devleti’nin dağılmasını önlemek için Osmanlıcılık, İslamcılık, Türkçülük ve Batıcılık fikir akımları ortaya çıktı. Osmanlıcılık, tüm vatandaşları eşit kabul ederek devleti bir arada tutmayı amaçladı. İslamcılık Müslümanları halife etrafında birleştirmeyi, Türkçülük ise Türk millî bilincini güçlendirmeyi hedefledi. Batıcılık, devletin Avrupa örnek alınarak çağdaşlaştırılmasını savundu.'),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Trablusgarp ve Balkan Savaşları', 2, 'Trablusgarp Savaşı, İtalya’nın Osmanlı’nın Kuzey Afrika’daki son toprağına saldırmasıyla başladı. Mustafa Kemal Derne ve Tobruk’ta başarı kazandı; Uşi Antlaşması ile Trablusgarp ve Bingazi İtalya’ya bırakıldı. Balkan Savaşları sonunda Osmanlı Balkanlardaki topraklarının büyük kısmını kaybetti, ancak II. Balkan Savaşı sırasında Edirne geri alındı. Balkan milletlerinin ayrılması Osmanlıcılık fikrinin geçerliliğini büyük ölçüde yitirmesine yol açtı.'),
  ('I. Dünya Savaşı Sürecinde Osmanlı', 'Savaşın Nedenleri ve Girilmesi', 1, 'I. Dünya Savaşı’nın temel nedenleri sömürgecilik yarışı, silahlanma, bloklaşma ve milliyetçilik akımıdır. Osmanlı Devleti, Almanya ile 2 Ağustos 1914’te ittifak yaptı. Yavuz ve Midilli gemilerinin Rus limanlarını bombalamasıyla Osmanlı savaşa fiilen girdi. Osmanlı yönetimi savaşla kaybedilen toprakları geri almayı ve Almanya’nın desteğinden yararlanmayı amaçladı.'),
  ('I. Dünya Savaşı Sürecinde Osmanlı', 'Cepheler', 2, 'Kafkas Cephesi’nde Sarıkamış Harekâtı başarısız oldu, ancak Mustafa Kemal Muş ve Bitlis’i geri aldı. Irak Cephesi’nde Halil Kut Paşa komutasında Kutü’l-Amâre Zaferi kazanıldı. Çanakkale Cephesi’nde Mustafa Kemal Anafartalar Kahramanı olarak tanındı ve İstanbul’un işgali önlendi. Hicaz Cephesi’nde Fahrettin Paşa Medine Müdafaası’nı yürüttü.'),
  ('I. Dünya Savaşı Sürecinde Osmanlı', 'Ermenilerin Sevk ve İskânı', 3, 'I. Dünya Savaşı sırasında Doğu Anadolu’daki güvenlik sorunları ve bazı Ermeni silahlı gruplarının faaliyetleri üzerine Sevk ve İskân Kanunu çıkarıldı. Kanunla savaş bölgesindeki Ermeni nüfusun bir bölümü Suriye ve Irak bölgelerine nakledildi. Uygulama savaş koşullarında yürütülmüş ve tarihî açıdan tartışmalı bir konu hâline gelmiştir. Konu değerlendirilirken dönemin savaş şartları ve farklı kaynaklar birlikte ele alınmalıdır.'),
  ('I. Dünya Savaşı''nın Sonuçları', 'Genel Sonuçlar', 1, 'I. Dünya Savaşı sonunda Osmanlı, Almanya, Avusturya-Macaristan ve Rusya gibi büyük imparatorluklar yıkıldı. Avrupa’da yeni ulus devletler kuruldu. Barışı korumak amacıyla Milletler Cemiyeti oluşturuldu. Sömürgeciliğin yerini manda ve himaye sistemi aldı; savaş sonrası Avrupa’da yeni siyasi rejimler ortaya çıktı.'),
  ('I. Dünya Savaşı''nın Sonuçları', 'Mondros Ateşkes Antlaşması (1918)', 2, 'Mondros Ateşkes Antlaşması 30 Ekim 1918’de imzalandı ve Osmanlı Devleti savaştan çekildi. 7. madde, İtilaf Devletlerine güvenlik gerekçesiyle istedikleri stratejik noktayı işgal etme hakkı verdi. 24. madde ise Vilayet-i Sitte’de karışıklık çıkması durumunda işgal yolunu açtı. Ateşkesten sonra ilk işgal edilen Osmanlı toprağı Musul oldu.'),
  ('Millî Mücadele''ye Hazırlık Dönemi-I', 'İzmir''in İşgali ve Kuvay-ı Milliye', 1, '15 Mayıs 1919’da İzmir’in Yunanistan tarafından işgali, Millî Mücadele’nin yayılmasını hızlandırdı. Hasan Tahsin’in ilk kurşunu atması direnişin sembollerinden biri oldu. İşgallere karşı halkın oluşturduğu bölgesel direniş birliklerine Kuvay-ı Milliye denir. Amiral Bristol Raporu, Yunan işgalinin haksızlığını ortaya koyan ilk uluslararası belge olarak kabul edilir.'),
  ('Millî Mücadele''ye Hazırlık Dönemi-I', 'Cemiyetler', 2, 'İşgaller karşısında Türk halkı millî cemiyetler kurarak bölgesel direnişi örgütledi. Redd-i İlhak ve Trakya-Paşaeli gibi cemiyetler vatanın bütünlüğünü korumayı amaçladı. Azınlık cemiyetleri ise bağımsız devlet kurmak için çalıştı. İngiliz Muhipleri ve Wilson Prensipleri Cemiyeti gibi bazı kuruluşlar manda ve himaye fikrini savundu.'),
  ('Millî Mücadele''ye Hazırlık Dönemi-II', 'Havza ve Amasya Genelgeleri', 1, 'Havza Genelgesi ile işgallere karşı miting ve protesto yapılması istendi. Amasya Genelgesi, Millî Mücadele’nin gerekçe, amaç ve yöntemini ilk kez açıklayan belgedir. Genelgede milletin bağımsızlığını yine milletin azim ve kararının kurtaracağı vurgulandı. Bu durum millî egemenlik anlayışının açık biçimde ortaya konduğunu gösterir.'),
  ('Millî Mücadele''ye Hazırlık Dönemi-II', 'Erzurum ve Sivas Kongreleri', 2, 'Erzurum Kongresi’nde millî sınırlardan ilk kez söz edildi, manda ve himaye ilk kez reddedildi ve Temsil Heyeti oluşturuldu. Sivas Kongresi’nde bütün yararlı cemiyetler Anadolu ve Rumeli Müdafaa-i Hukuk Cemiyeti altında birleştirildi. Manda ve himaye kesin olarak reddedildi. Sivas Kongresi ulusal nitelikte olması bakımından Millî Mücadele’nin önemli dönüm noktalarındandır.'),
  ('Millî Mücadele''ye Hazırlık Dönemi-II', 'Amasya Görüşmeleri ve Misak-ı Milli', 3, 'Amasya Görüşmeleri ile İstanbul Hükûmeti, Temsil Heyeti’ni resmen tanıdı. Son Osmanlı Mebusan Meclisi Misak-ı Millî kararlarını kabul ederek millî sınırları ve bağımsızlık hedeflerini belirledi. Bunun üzerine İstanbul 16 Mart 1920’de resmen işgal edildi. İşgal sonrasında birçok milletvekili Ankara’ya geçerek BMM’nin açılmasına katkı sağladı.'),
  ('Büyük Millet Meclisi''nin Açılması ve Sevr', 'BMM''nin Açılması ve İsyanlar', 1, '23 Nisan 1920’de Ankara’da BMM açıldı ve millî egemenlik anlayışı benimsendi. Yasama ve yürütme yetkilerinin mecliste toplanmasıyla güçler birliği ilkesi uygulandı. BMM’ye karşı çıkan isyanlarla mücadele için Hıyanet-i Vataniye Kanunu çıkarıldı ve İstiklal Mahkemeleri kuruldu. Meclis Hükûmeti Sistemi, olağanüstü savaş şartlarında hızlı karar almayı amaçladı.'),
  ('Büyük Millet Meclisi''nin Açılması ve Sevr', 'Sevr Antlaşması', 2, 'Sevr Antlaşması 10 Ağustos 1920’de Osmanlı Devleti’ne kabul ettirilmeye çalışıldı. Antlaşma Anadolu’yu büyük ölçüde parçalamayı ve Osmanlı Devleti’ni siyasi, askerî ve ekonomik açıdan etkisiz bırakmayı hedefliyordu. Osmanlı Mebusan Meclisi tarafından onaylanmadığı için hukuken yürürlüğe girmedi. BMM Sevr’i tanımadı ve antlaşmayı imzalayanları vatan haini saydı.'),
  ('Doğu, Güney ve Batı Cepheleri', 'Doğu ve Güney Cepheleri', 1, 'Doğu Cephesi’nde Kazım Karabekir komutasındaki Türk ordusu Ermenilere karşı başarı kazandı. 3 Aralık 1920 Gümrü Antlaşması, BMM’nin imzaladığı ilk siyasi antlaşmadır. Güney Cephesi’nde düzenli ordudan çok halk direnişi etkili oldu; Maraş, Urfa ve Antep halkı önemli mücadeleler verdi. 1921 Ankara Antlaşması ile Fransa ile savaş sona erdi.'),
  ('Doğu, Güney ve Batı Cepheleri', 'Batı Cephesi I. ve II. İnönü Muharebeleri', 2, 'I. İnönü Zaferi, düzenli ordunun Batı Cephesi’ndeki ilk askerî başarısıdır. Zafer sonrasında BMM Londra Konferansı’na davet edildi, 1921 Anayasası ve İstiklal Marşı kabul edildi. Moskova Antlaşması ile Sovyet Rusya BMM’yi tanıyan ilk Avrupa devleti oldu. II. İnönü Zaferi, düzenli orduya duyulan güveni artırdı.'),
  ('Doğu, Güney ve Batı Cepheleri', 'Kütahya-Eskişehir ve Sakarya Savaşları', 3, 'Kütahya-Eskişehir Savaşları sonrasında Türk ordusu Sakarya Nehri’nin doğusuna çekildi. Mustafa Kemal Başkomutan seçildi ve Tekâlif-i Millîye Emirleri yayımlandı. Sakarya Meydan Muharebesi ile Türk ordusunun geri çekilişi sona erdi. Bu zaferden sonra Türk ordusu savunmadan taarruza geçme fırsatı buldu.'),
  ('Millî Mücadele''nin Sona Ermesi', 'Büyük Taarruz ve Mudanya', 1, 'Büyük Taarruz 26 Ağustos 1922’de başladı ve 30 Ağustos Başkomutanlık Meydan Muharebesi ile kesin zafer kazanıldı. Yunan ordusu Batı Anadolu’dan çıkarıldı ve askerî mücadele büyük ölçüde sona erdi. 11 Ekim 1922 Mudanya Ateşkesi ile Doğu Trakya, İstanbul ve Boğazlar savaşılmadan geri alındı. Mudanya, Lozan Barış Konferansı’nın yolunu açtı.'),
  ('Millî Mücadele''nin Sona Ermesi', 'Lozan Barış Antlaşması', 2, 'Lozan Barış Antlaşması 24 Temmuz 1923’te imzalandı ve Türkiye’nin bağımsızlığı uluslararası alanda kabul edildi. Kapitülasyonlar kaldırıldı, Düyûn-ı Umûmiye İdaresi sona erdi ve azınlıklar Türk vatandaşı kabul edildi. Musul sorunu çözülemedi; Boğazlar askersizleştirilmiş uluslararası komisyonun denetimine bırakıldı. Lozan, Sevr Antlaşması’nı geçersiz kılan temel barış antlaşmasıdır.'),
  ('Atatürk İlkeleri-Siyasi ve Hukuki Gelişmeler', 'Siyasi Alanda İnkılaplar', 1, '1 Kasım 1922’de saltanat kaldırılarak millî egemenlik anlayışı güçlendirildi. 13 Ekim 1923’te Ankara başkent oldu, 29 Ekim 1923’te Cumhuriyet ilan edildi. 3 Mart 1924’te halifelik kaldırılarak laikleşme yolunda önemli bir adım atıldı. 1924 Anayasası ile yeni devletin temel yapısı düzenlendi.'),
  ('Atatürk İlkeleri-Siyasi ve Hukuki Gelişmeler', 'Hukuk Alanı ve Medeni Kanun', 2, '1926’da İsviçre Medeni Kanunu örnek alınarak Türk Medeni Kanunu kabul edildi. Mecelle kaldırıldı ve hukuk birliği güçlendirildi. Kadınlara mirasta eşitlik, boşanma davası açma ve meslek seçme gibi sosyal-ekonomik haklar tanındı. Tek eşlilik ve resmî nikâh zorunlu hâle getirildi; kadınlara siyasi haklar ise sonraki yıllarda verildi.'),
  ('Atatürk Dönemi''nde Yapılan İnkılaplar', 'Eğitim, Kültür ve Toplumsal İnkılaplar', 1, 'Tevhid-i Tedrisat Kanunu ile bütün eğitim kurumları Millî Eğitim Bakanlığına bağlandı ve eğitimde birlik sağlandı. Harf İnkılabı ile Latin esaslı Türk alfabesi kabul edildi; Millet Mektepleri açılarak okuma yazma seferberliği başlatıldı. Türk Tarih Kurumu ve Türk Dil Kurumu kuruldu. Soyadı Kanunu, kılık-kıyafet düzenlemeleri ile takvim, saat ve ölçülerde yapılan değişiklikler toplumsal modernleşmeyi destekledi.'),
  ('Atatürk Dönemi''nde Yapılan İnkılaplar', 'Ekonomi Alanındaki Gelişmeler', 2, 'İzmir İktisat Kongresi’nde millî ve bağımsız ekonomi hedefi benimsendi. Aşar vergisi kaldırılarak çiftçilerin yükü hafifletildi; Kabotaj Kanunu ile Türk denizciliği desteklendi. 1929 Dünya Ekonomik Bunalımı sonrasında devletçilik ilkesi öne çıktı. Sümerbank ve Merkez Bankası gibi kurumlar kuruldu, devlet eliyle fabrikalar ve sanayi yatırımları artırıldı.')
) as d(unit_title, title, sort_order, summary)
join public.units u on u.subject_id = 'tarih' and u.title = d.unit_title;

-- SORULAR (240)
insert into public.questions (topic_id, prompt, options, correct_index, explanation, difficulty)
select t.id, d.prompt, d.options::jsonb, d.correct_index, d.explanation, d.difficulty
from (values
  ('İnsanlığın Hafızası Tarih', 'Tarih Bilimi ve Konusu', 'Tarihin diğer sosyal bilimlerden ayrılan en belirgin özelliği aşağıdakilerden hangisidir?', '["İnsan topluluklarını yalnızca ekonomik yönüyle incelemesi","Olayları deney ve gözlem yoluyla tekrar edebilmesi","İnsan faaliyetlerini yer, zaman ve sebep-sonuç ilişkisi içinde belgelere dayalı incelemesi","Yalnızca devletler arası savaşları konu edinmesi","Doğanın fiziksel özelliklerini araştırması"]', 2, 'Tarih, insan topluluklarının geçmişteki faaliyetlerini yer ve zaman göstererek; sebep-sonuç ilişkisi içinde belgelere dayanarak inceler.', 2),
  ('İnsanlığın Hafızası Tarih', 'Tarih Bilimi ve Konusu', 'Bir tarihçinin geçmişte yaşanan bir olayı bugünün değer yargılarıyla değil, yaşandığı dönemin koşullarıyla değerlendirmesi aşağıdakilerden hangisini gösterir?', '["Tarihî olayların tekrarlanabileceğini","Tarihî bilginin yalnızca sözlü kaynaklara dayandığını","Tarihî olayların kendi dönemi içinde ele alınması gerektiğini","Tarihte kesin kanunların bulunduğunu","Tarihin deneysel bir bilim olduğunu"]', 2, 'Tarihî olaylar doğru yorumlanabilmek için yaşandıkları dönemin siyasi, sosyal ve kültürel şartları içinde değerlendirilmelidir.', 2),
  ('İnsanlığın Hafızası Tarih', 'Kaynakların Sınıflandırılması', 'Aşağıdakilerden hangisi birinci el tarihî kaynağa örnektir?', '["Ders kitabı","Ansiklopedi","Olay dönemine ait ferman","Belgesel film","Tarih araştırma kitabı"]', 2, 'Birinci el kaynaklar, olayın yaşandığı döneme ait belge ve buluntulardır. Fermanlar dönemin resmî belgeleri olduğu için birinci el kaynaktır.', 1),
  ('İnsanlığın Hafızası Tarih', 'Kaynakların Sınıflandırılması', 'Bir tarihçinin Osmanlı dönemine ait kitabe, para ve fermanları incelemesi öncelikle hangi tür kaynaklardan yararlandığını gösterir?', '["İkinci el kaynaklar","Sözlü kaynaklar","Birinci el kaynaklar","Edebî kaynaklar","Yardımcı kaynaklar"]', 2, 'Kitabe, para ve ferman olayın yaşandığı döneme ait olduğu için birinci el tarihî kaynak sayılır.', 2),
  ('İnsanlığın Hafızası Tarih', 'Tarihe Yardımcı Bilim Dalları', 'Tarih öncesi dönemlerin aydınlatılmasında tarihe en çok yardımcı olan bilim dalı aşağıdakilerden hangisidir?', '["Paleografya","Nümismatik","Arkeoloji","Epigrafi","Filoloji"]', 2, 'Arkeoloji kazılar yoluyla toprak ve su altındaki maddi kalıntıları ortaya çıkarır. Tarih öncesi dönemlerde yazı olmadığı için en çok arkeolojiden yararlanılır.', 1),
  ('İnsanlığın Hafızası Tarih', 'Tarihe Yardımcı Bilim Dalları', 'Aşağıdaki bilim dallarından hangisinin eşleştirmesi doğrudur?', '["Nümismatik - Eski yazıları inceleme","Paleografya - Paraları inceleme","Epigrafi - Kitabe ve mezar taşlarındaki yazıları inceleme","Kronoloji - Toplumların geleneklerini inceleme","Etnografya - Devlet armalarını inceleme"]', 2, 'Epigrafi, kitabe, anıt ve mezar taşları üzerindeki yazıları inceler.', 2),
  ('Zamanın Taksimi', 'Takvim Sistemlerinin Doğuşu', 'Tarihte bilinen ilk Ay yılı esaslı takvimi kullanan uygarlık aşağıdakilerden hangisidir?', '["Mısırlılar","Sümerler","Romalılar","Yunanlar","İbraniler"]', 1, 'Sümerler, Ay’ın Dünya etrafındaki hareketini esas alan ilk takvimi kullanmıştır.', 1),
  ('Zamanın Taksimi', 'Takvim Sistemlerinin Doğuşu', 'Aşağıdaki eşleştirmelerden hangisi doğrudur?', '["Müslümanlar - İlk Olimpiyat Oyunları","Hristiyanlar - Hz. Muhammed’in hicreti","Yunanlar - MÖ 776 İlk Olimpiyat Oyunları","İbraniler - Hz. İsa’nın doğumu","Romalılar - Yaradılış yılı"]', 2, 'Yunanlar takvim başlangıcı olarak ilk olimpiyat oyunlarının yapıldığı MÖ 776 yılını kabul etmiştir.', 2),
  ('Zamanın Taksimi', 'Türklerin Kullandığı Takvimler', 'Aşağıdakilerden hangisi Türklerin kullandığı ilk takvimdir?', '["Hicrî Takvim","Celâlî Takvim","Rûmî Takvim","On İki Hayvanlı Türk Takvimi","Miladi Takvim"]', 3, 'On İki Hayvanlı Türk Takvimi, Türklerin kullandığı ilk takvimdir; Güneş yılı esaslıdır ve yıllar hayvan adlarıyla gösterilir.', 1),
  ('Zamanın Taksimi', 'Türklerin Kullandığı Takvimler', 'Osmanlı Devleti’nde mali işlerin düzenlenmesi amacıyla kullanılan takvim aşağıdakilerden hangisidir?', '["Hicrî Takvim","Celâlî Takvim","Rûmî Takvim","On İki Hayvanlı Türk Takvimi","Miladi Takvim"]', 2, 'Rûmî Takvim, Osmanlı Devleti’nde özellikle mali işlerin düzenlenmesi amacıyla kullanılmıştır.', 2),
  ('Zamanın Taksimi', 'Türklerin Kullandığı Takvimler', 'Hicrî Takvim ile ilgili aşağıdakilerden hangisi doğrudur?', '["Güneş yılı esasına dayanır","Başlangıç yılı 1079’dur","Yıllar hayvan adlarıyla gösterilir","Hz. İsa’nın doğumunu başlangıç kabul eder","Hz. Muhammed’in hicretini başlangıç kabul eder"]', 4, 'Hicrî Takvim Ay yılı esaslıdır ve başlangıç olarak 622 yılındaki Hicret’i kabul eder.', 2),
  ('Avrasya''da İlk Türk İzleri', 'Avrasya ve Türk Adı', 'Türk adının anlamı ile ilgili aşağıdakilerden hangisi doğru bir bilgi değildir?', '["Güçlü ve kuvvetli anlamında kullanılmıştır","Türeyiş ve çoğalma anlamıyla ilişkilendirilmiştir","Töreli, düzenli anlamında yorumlanmıştır","Yalnızca belirli bir boyun adı olarak kullanılmıştır","Olgunluk çağı anlamıyla açıklanmıştır"]', 3, 'Türk adı yalnızca belirli bir boyun adı değildir; zamanla siyasi ve etnik bir ad olarak geniş bir topluluğu ifade etmiştir.', 2),
  ('Avrasya''da İlk Türk İzleri', 'Avrasya ve Türk Adı', 'Türk adını devlet adı olarak kullanan ilk Türk devleti aşağıdakilerden hangisidir?', '["Asya Hun Devleti","Avrupa Hun Devleti","I. Kök Türk Devleti","Uygur Devleti","Hazar Devleti"]', 2, 'Türk adını devlet adı olarak kullanan ilk Türk devleti I. Kök Türk Devleti’dir.', 1),
  ('Avrasya''da İlk Türk İzleri', 'Orta Asya Kültür Merkezleri', 'Aşağıdaki kültür merkezlerinden hangisi Türklerde atın evcilleştirildiği ve atlı göçebe yaşamın geliştiği yerlerden biri olarak kabul edilir?', '["Anav","Afanasyevo","Andronova","Karasuk","Taspar"]', 1, 'Afanasyevo Kültürü, atın evcilleştirilmesi ve atlı göçebe yaşamın gelişimiyle ilişkilendirilir.', 2),
  ('Avrasya''da İlk Türk İzleri', 'Orta Asya Kültür Merkezleri', 'Türk kültür çevresinde demirin işlenmesi ve savaş araçlarının gelişmesiyle öne çıkan kültür merkezi aşağıdakilerden hangisidir?', '["Anav","Afanasyevo","Andronova","Karasuk","Taş Devri"]', 3, 'Karasuk Kültürü’nde demir işçiliği ilerlemiş, silah ve savaş araçlarında önemli gelişmeler görülmüştür.', 2),
  ('Avrasya''da İlk Türk İzleri', 'Bozkır Coğrafyası ve Askerî Kültür', 'Bozkır coğrafyasının Türk toplumlarında aşağıdakilerden hangisinin gelişmesinde daha etkili olduğu söylenebilir?', '["Deniz ticaretinin","Şehir devletlerinin","Atlı savaşçılığın ve hareketli orduların","Derebeylik sisteminin","Toprağa bağlı köylü düzeninin"]', 2, 'Bozkır yaşamı, hayvancılığa dayalı hareketli hayatı ve atlı savaşçılığı geliştirmiştir.', 1),
  ('Avrasya''da İlk Türk İzleri', 'Bozkır Coğrafyası ve Askerî Kültür', 'İlk Türk devletlerinde uygulanan onlu sistemin temel amacı aşağıdakilerden hangisidir?', '["Vergi gelirlerini artırmak","Orduyu düzenli ve kolay yönetilebilir hâle getirmek","Tarım üretimini denetlemek","Dinî törenleri düzenlemek","Şehirlerde güvenliği sağlamak"]', 1, 'Onlu sistem, ordunun on, yüz, bin ve on binlik birliklere ayrılarak düzenli biçimde yönetilmesini sağlamıştır.', 2),
  ('Avrasya''da İlk Türk İzleri', 'Bozkır Coğrafyası ve Askerî Kültür', 'Türk savaş taktiklerinden biri olan Turan Taktiği’nin temel özelliği aşağıdakilerden hangisidir?', '["Kaleleri uzun süre kuşatmak","Doğrudan merkezden saldırmak","Sahte geri çekilme ile düşmanı çember içine almak","Yalnızca gece baskınları yapmak","Düşmanı aç bırakmak"]', 2, 'Turan Taktiği’nde birlikler geri çekiliyor gibi yaparak düşmanı uygun alana çeker ve çevreleyerek saldırır.', 2),
  ('Boylardan Devlete-I', 'Türklerde Sosyal Yapı', 'İlk Türk devletlerinde toplumun en küçük sosyal birimi aşağıdakilerden hangisidir?', '["Boy","Budun","Oguş","İl","Uluf"]', 4, 'İlk Türk toplumunda aileye oguş denirdi. Oguşların birleşmesiyle urug, urugların birleşmesiyle boy, boyların birleşmesiyle budun oluşurdu.', 1),
  ('Boylardan Devlete-I', 'Türklerde Sosyal Yapı', 'İlk Türk devletlerinde boyların birleşmesiyle oluşan ve ortak dil, kültür ile siyasi bağ taşıyan topluluğa ne ad verilirdi?', '["Oguş","Urug","Budun","İl","Toy"]', 2, 'Budun, boyların birleşmesiyle oluşan millet anlamındaki topluluktur.', 2),
  ('Boylardan Devlete-I', 'Kut Anlayışı ve Devlet Teşkilatı', 'İlk Türk devletlerinde hükümdara devleti yönetme yetkisinin Gök Tanrı tarafından verildiğine inanılması aşağıdaki kavramlardan hangisiyle açıklanır?', '["Töre","Kut","Kurgan","Toy","Tamga"]', 1, 'Kut anlayışına göre hükümdarlık yetkisi Gök Tanrı tarafından hanedana verilirdi.', 1),
  ('Boylardan Devlete-I', 'Kut Anlayışı ve Devlet Teşkilatı', 'Aşağıdakilerden hangisi ilk Türk devletlerinde hükümdarın yetkilerini sınırlayan unsurlardan biri değildir?', '["Töre","Kurultay","Kut anlayışı","Halkın gelenekleri","Hükümdarın keyfî kararları"]', 4, 'Töre, kurultay ve gelenekler hükümdarın yetkilerini sınırlandırırdı. Hükümdarın keyfî kararları ise sınırlayıcı değil, aksine sınırsız yönetim anlayışını ifade eder.', 2),
  ('Boylardan Devlete-II', 'Asya Hun ve I. Kök Türk Devletleri', 'Asya Hun Devleti’nin en güçlü hükümdarı kabul edilen ve Çin’e karşı mücadele eden hükümdar aşağıdakilerden hangisidir?', '["Teoman","Mete Han","Bumin Kağan","Kutluk Kağan","Bilge Kağan"]', 1, 'Mete Han, Asya Hun Devleti’nin en güçlü hükümdarıdır. Çin’e karşı mücadele etmiş ve Türk ordusundaki onlu sistemi geliştirmiştir.', 1),
  ('Boylardan Devlete-II', 'Asya Hun ve I. Kök Türk Devletleri', 'I. Kök Türk Devleti’nin kısa sürede geniş bir coğrafyada hâkimiyet kurmasında aşağıdakilerden hangisinin etkili olduğu söylenebilir?', '["Deniz ticaretine ağırlık vermesi","İpek Yolu’na hâkim olmak istemesi","Feodal yönetim uygulaması","Yerleşik tarıma geçmesi","Avrupa devletleriyle ittifak kurması"]', 1, 'I. Kök Türk Devleti, İpek Yolu’nun denetimini ele geçirmek için mücadele etmiş; bu durum siyasi ve ekonomik gücünü artırmıştır.', 2),
  ('Boylardan Devlete-II', 'II. Kök Türk ve Uygur Devletleri', 'II. Kök Türk Devleti’nde Türk tarihinin ilk yazılı belgeleri kabul edilen Orhun Yazıtları aşağıdaki hükümdarlardan hangisi döneminde dikilmiştir?', '["Mete Han","Attila","Bilge Kağan","Bumin Kağan","İstemi Yabgu"]', 2, 'Orhun Yazıtları, Bilge Kağan, Kültigin ve Tonyukuk adına dikilmiştir. Türk tarihinin ilk yazılı belgeleri kabul edilir.', 1),
  ('Boylardan Devlete-II', 'II. Kök Türk ve Uygur Devletleri', 'Uygurların Maniheizm dinini kabul etmelerinin aşağıdakilerden hangisine ortam hazırladığı söylenebilir?', '["Savaşçı özelliklerinin güçlenmesine","Konar-göçer yaşamın tamamen yayılmasına","Yerleşik yaşama ve şehir kültürüne yönelmelerine","İpek Yolu üzerindeki hâkimiyetlerinin sona ermesine","Kut anlayışının ortadan kalkmasına"]', 2, 'Maniheizm et yemeyi ve savaşçılığı sınırlayan yönleriyle Uygurları yerleşik yaşama, tarıma ve şehir kültürüne yöneltmiştir.', 2),
  ('Boylardan Devlete-II', 'İlk Türk Devletlerinde Töre', 'İlk Türk devletlerinde yazısız hukuk kurallarına verilen ad aşağıdakilerden hangisidir?', '["Kut","Töre","Tamga","Kurgan","Şölen"]', 1, 'Töre, ilk Türk devletlerinde toplum ve devlet hayatını düzenleyen yazısız hukuk kurallarıdır.', 1),
  ('Boylardan Devlete-II', 'İlk Türk Devletlerinde Töre', 'Aşağıdakilerden hangisi ilk Türk devletlerinde törenin oluşmasında etkili olan unsurlardan biri değildir?', '["Hükümdar kararları","Kurultay kararları","Halkın gelenekleri","Gök Tanrı inancı","Yazılı anayasa hükümleri"]', 4, 'Töre; gelenekler, kurultay kararları ve hükümdar emirleriyle oluşurdu. İlk Türk devletlerinde modern anlamda yazılı anayasa yoktur.', 2),
  ('Kavimler Göçü', 'Kavimler Göçü ve Sonuçları', 'Kavimler Göçü''nün başlamasında etkili olan temel gelişme aşağıdakilerden hangisidir?', '["Roma İmparatorluğu''nun ikiye ayrılması","Hunların batıya doğru ilerlemesi","Feodalitenin güçlenmesi","İlk Çağ''ın sona ermesi","Avrupa milletlerinin kurulması"]', 1, 'Hunların Balamir önderliğinde batıya ilerlemesi, Germen kavimlerini Roma topraklarına yöneltmiş ve Kavimler Göçü''nü başlatmıştır.', 1),
  ('Kavimler Göçü', 'Kavimler Göçü ve Sonuçları', 'Aşağıdakilerden hangisi Kavimler Göçü''nün Avrupa''daki sonuçlarından biri değildir?', '["Roma İmparatorluğu''nun Doğu ve Batı olarak ayrılması","Feodalitenin güç kazanması","Skolastik düşüncenin yayılması","Avrupa milletlerinin temellerinin atılması","Merkezî krallıkların hemen güçlenmesi"]', 4, 'Kavimler Göçü sonrasında Avrupa''da merkezî krallıklar değil, derebeylik yani feodalite güç kazanmıştır.', 2),
  ('Kavimler Göçü', 'Avrupa Hun Devleti', 'Avrupa Hun Devleti''nin en güçlü dönemi aşağıdaki hükümdarlardan hangisi zamanında yaşanmıştır?', '["Balamir","Uldız","Attila","Mete Han","Bilge Kağan"]', 2, 'Avrupa Hun Devleti, Attila döneminde siyasi ve askerî açıdan en geniş etki alanına ulaşmıştır.', 1),
  ('Kavimler Göçü', 'Avrupa Hun Devleti', 'Attila''nın Doğu Roma''yı vergiye bağlamasında etkili olan antlaşmalar aşağıdakilerden hangisidir?', '["Karadeniz ve İstanbul","Karlofça ve Pasarofça","Margus ve Anatolios","Prut ve Belgrad","Zitvatorok ve Bucaş"]', 2, 'Attila, Doğu Roma ile yaptığı Margus ve Anatolios Antlaşmaları sonucunda Doğu Roma''yı vergiye bağlamıştır.', 2),
  ('Kavimler Göçü', 'Diğer Türk Boyları', 'Aşağıdaki Türk boylarından hangisi Museviliği benimseyen tek Türk devleti olarak bilinir?', '["Avarlar","Hazarlar","Karluklar","Peçenekler","Kıpçaklar"]', 1, 'Hazarlar, Museviliği benimseyen tek Türk devleti olarak bilinir.', 1),
  ('Kavimler Göçü', 'Diğer Türk Boyları', 'Aşağıdaki eşleştirmelerden hangisi doğrudur?', '["Avarlar - Talas Savaşı''nda Abbasilere yardım etmiştir","Karluklar - İstanbul''u kuşatan ilk Türk devletidir","Peçenekler - Malazgirt Savaşı''nda Selçukluların yanında yer almıştır","Hazarlar - Maniheizmi kabul etmiştir","Uygurlar - Museviliği benimsemiştir"]', 2, 'Peçenekler, 1071 Malazgirt Savaşı''nda Büyük Selçuklu Devleti''nin yanında Bizans''a karşı mücadele etmiştir.', 2),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'İslam Öncesi Arap Yarımadası', 'İslamiyet öncesinde Arap Yarımadası''nda siyasi birlik bulunmaması ve kabileciliğin etkili olması bu dönemin hangi adla anılmasına ortam hazırlamıştır?', '["Hicret Dönemi","Asr-ı Saadet","Cahiliye Dönemi","Emeviler Dönemi","Abbasiler Dönemi"]', 2, 'İslamiyet öncesindeki siyasi, sosyal ve dinî yapı nedeniyle bu dönem Cahiliye Dönemi olarak adlandırılır.', 1),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'İslam Öncesi Arap Yarımadası', 'Haram aylarda savaş yapılması yasak olmasına rağmen gerçekleştirilen savaşlara ne ad verilmiştir?', '["Bedir Savaşları","Ficâr Savaşları","Yermük Savaşı","Cemel Vakası","Sıffin Savaşı"]', 1, 'Haram aylarda yapılması yasak olduğu hâlde gerçekleşen savaşlara Ficâr Savaşları denilmiştir.', 2),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'Dört Halife Dönemi', 'Dört Halife Dönemi''nin Cumhuriyet Dönemi olarak da adlandırılmasının temel nedeni aşağıdakilerden hangisidir?', '["Halifeliğin babadan oğula geçmesi","Halifelerin seçimle iş başına gelmesi","Devlet merkezinin Bağdat olması","Türklerin orduya alınması","Mevali politikasının uygulanması"]', 1, 'Dört Halife Dönemi''nde halifeler seçim yoluyla belirlenmiştir; bu nedenle dönem Cumhuriyet Dönemi olarak da anılır.', 1),
  ('İslamiyet''in Doğduğu Dönemde Dünya', 'Dört Halife Dönemi', 'Aşağıdaki gelişmelerden hangisi Hz. Osman döneminde yaşanmıştır?', '["Kur''an-ı Kerim''in kitap hâline getirilmesi","İran, Irak, Suriye ve Mısır''ın fethedilmesi","İlk İslam donanmasının kurulması","Cemel Vakası''nın yaşanması","Hicret''in gerçekleşmesi"]', 2, 'Hz. Osman döneminde ilk İslam donanması kurulmuş ve Kur''an-ı Kerim çoğaltılarak eyaletlere gönderilmiştir.', 2),
  ('Emeviler', 'Emevi Siyaseti ve Mevali Politikası', 'Emeviler döneminde halifeliğin saltanata dönüşmesine neden olan gelişme aşağıdakilerden hangisidir?', '["Muaviye''nin oğlu Yezid''i veliaht göstermesi","Hz. Ebubekir''in halife seçilmesi","Abbasilerin Bağdat''ı başkent yapması","Talas Savaşı''nın yapılması","İlk İslam donanmasının kurulması"]', 0, 'Muaviye''nin oğlu Yezid''i veliaht ilan etmesiyle halifelik seçimle belirlenen bir makam olmaktan çıkıp saltanata dönüşmüştür.', 1),
  ('Emeviler', 'Emevi Siyaseti ve Mevali Politikası', 'Emevilerin Arap olmayan Müslümanlara ikinci sınıf muamele yapmasına verilen ad aşağıdakilerden hangisidir?', '["İstimâlet","Devşirme","Mevali","Tımar","Malikâne"]', 2, 'Mevali politikası, Emevilerin Arap olmayan Müslümanlara uyguladığı ayrımcı siyasettir.', 1),
  ('Emeviler', 'Emevi Siyaseti ve Mevali Politikası', 'Mevali politikasının Türk tarihi açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Türklerin İslamiyet''i kabulünün gecikmesi","Anadolu''nun Türkleşmesi","İlk Türk devletlerinin yıkılması","Haçlı Seferlerinin başlaması","İstanbul''un fethedilmesi"]', 0, 'Mevali politikası Türkler arasında İslamiyet''in yayılmasını geciktirmiş ve Emevilere karşı tepki oluşturmuştur.', 2),
  ('Abbasi Devleti ve Türkler - Bilim', 'Abbasiler ve Mısır''da Kurulan Türk Devletleri', 'Abbasilerin Türklerle ilişkilerinde Emevilerden farklı bir siyaset izlediğini gösteren uygulama aşağıdakilerden hangisidir?', '["Mevali politikasını sürdürmeleri","Türkleri ordu ve devlet yönetiminde görevlendirmeleri","Halifeliği saltanata dönüştürmeleri","İstanbul''u kuşatmaları","Kerbela Olayı''nı gerçekleştirmeleri"]', 1, 'Abbasiler Mevali anlayışını kaldırarak Türklerin askerî ve idarî görevlerde daha fazla yer almasını sağlamıştır.', 2),
  ('Abbasi Devleti ve Türkler - Bilim', 'Abbasiler ve Mısır''da Kurulan Türk Devletleri', 'Mısır''da kurulan ilk Müslüman Türk devleti aşağıdakilerden hangisidir?', '["Tolunoğulları","İhşidiler","Eyyubiler","Memlükler","Karahanlılar"]', 0, 'Tolunoğulları, Mısır''da kurulan ilk Müslüman Türk devletidir.', 1),
  ('Abbasi Devleti ve Türkler - Bilim', 'Abbasiler ve Mısır''da Kurulan Türk Devletleri', 'Selahaddin Eyyubi''nin Hıttin Savaşı''ndaki başarısının en önemli sonucu aşağıdakilerden hangisidir?', '["İstanbul''un fethedilmesi","Kudüs''ün Haçlılardan geri alınması","Anadolu''nun Türkleşmesi","Endülüs''ün kurulması","Moğolların yenilmesi"]', 1, '1187 Hıttin Savaşı sonrasında Selahaddin Eyyubi, Kudüs''ü Haçlılardan geri almıştır.', 2),
  ('Abbasi Devleti ve Türkler - Bilim', 'İslam Medeniyetinde Âlimler', 'El-Kanun fi''t-Tıbb adlı eseriyle tıp alanında tanınan İslam âlimi aşağıdakilerden hangisidir?', '["Farabi","Gazali","İbn Sina","İbn Rüşd","Kaşgarlı Mahmut"]', 2, 'İbn Sina, El-Kanun fi''t-Tıbb adlı eseriyle tıp alanında hem İslam dünyasını hem Avrupa''yı etkilemiştir.', 1),
  ('Abbasi Devleti ve Türkler - Bilim', 'İslam Medeniyetinde Âlimler', 'Aşağıdaki bilim insanı ve çalışma alanı eşleştirmelerinden hangisi doğrudur?', '["Farabi - Tıp","İbn Sina - Astronomi","Gazali - Dinî ilimler","İbn Rüşd - Coğrafya","Harezmi - Mimarlık"]', 2, 'Gazali dinî ilimler ve düşünce alanındaki çalışmalarıyla tanınır.', 2),
  ('Türklerin İslamiyet''i Kabulü', 'Talas Savaşı ve İlk Türk İslam Devletleri', '751 Talas Savaşı''nın Türk tarihi açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Anadolu''nun Türk yurdu hâline gelmesi","Türklerin İslamiyet''i benimseme sürecinin hızlanması","İstanbul''un fethedilmesi","Haçlı Seferlerinin sona ermesi","Osmanlı Devleti''nin kurulması"]', 1, 'Talas Savaşı Türklerle Müslüman Arapların yakınlaşmasını sağlamış ve Türklerin İslamiyet''i kabul sürecini hızlandırmıştır.', 1),
  ('Türklerin İslamiyet''i Kabulü', 'Talas Savaşı ve İlk Türk İslam Devletleri', 'Aşağıdaki eşleştirmelerden hangisi doğrudur?', '["Karahanlılar - Hindistan''a seferler düzenlemiştir","Gazneliler - Orta Asya''da kurulan ilk Müslüman Türk devletidir","Gazneli Mahmut - Sultan unvanını kullanan ilk Türk hükümdarıdır","Uygurlar - Talas Savaşı''nda Abbasilere yardım etmiştir","Tolunoğulları - Anadolu''da kurulan ilk Türk devleti"]', 2, 'Gazneli Mahmut, Abbasi halifesinden Sultan unvanını alan ilk Türk hükümdarıdır. Karahanlılar ise Orta Asya''daki ilk Müslüman Türk devletidir.', 2),
  ('Türklerin İslamiyet''i Kabulü', 'Talas Savaşı ve İlk Türk İslam Devletleri', 'Türklerin İslamiyet''i kabulünü kolaylaştıran unsurlardan biri aşağıdakilerden hangisidir?', '["Mevali politikasının uygulanması","Kök Tengri inancı ile İslamiyet arasındaki benzerlikler","Haçlı Seferleri''nin başlaması","Moğol istilalarının yaşanması","Bizans''ın Anadolu''daki gücünün artması"]', 1, 'Tek Tanrı, ahiret, kader ve ahlak anlayışı gibi benzerlikler Türklerin İslamiyet''e yakınlık duymasını kolaylaştırmıştır.', 2),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Devlet Anlayışı ve Hükümdarlık Sembolleri', 'İlk Türk-İslam devletlerinde hükümdarın yönetme yetkisinin halife tarafından onaylandığını gösteren uygulama aşağıdakilerden hangisidir?', '["Kut alma","Menşur alma","Toy düzenleme","Töre oluşturma","İkili teşkilat uygulama"]', 1, 'Menşur, halifenin hükümdarın egemenliğini tanıdığını gösteren belgedir.', 2),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Devlet Anlayışı ve Hükümdarlık Sembolleri', 'Hükümdarın sefere çıkarken veya törenlerde başının üzerinde tutulan ipek şemsiyeye ne ad verilir?', '["Tıraz","Çetr","Nevbet","Tuğra","Hutbe"]', 1, 'Çetr, Türk-İslam devletlerinde hükümdarlık sembolü olarak kullanılan ipek şemsiyedir.', 1),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Türk-İslam Dünyasında İlk Eserler', 'Aşağıdaki eser-yazar eşleştirmelerinden hangisi yanlıştır?', '["Kutadgu Bilig - Yusuf Has Hacip","Divânü Lugati''t-Türk - Kaşgarlı Mahmut","Divân-ı Hikmet - Ahmet Yesevi","Atabetü''l-Hakayık - Edip Ahmet Yükneki","Siyasetname - Kaşgarlı Mahmut"]', 4, 'Siyasetname''nin yazarı Nizamülmülk''tür. Kaşgarlı Mahmut ise Divânü Lugati''t-Türk''ü yazmıştır.', 2),
  ('İslamiyet''in Türk Toplumuna Etkisi', 'Türk-İslam Dünyasında İlk Eserler', 'Kaşgarlı Mahmut''un Araplara Türkçe öğretmek ve Türkçenin zenginliğini göstermek amacıyla yazdığı eser aşağıdakilerden hangisidir?', '["Kutadgu Bilig","Divân-ı Hikmet","Atabetü''l-Hakayık","Divânü Lugati''t-Türk","Siyasetname"]', 3, 'Divânü Lugati''t-Türk, Kaşgarlı Mahmut tarafından Türkçeyi Araplara öğretmek amacıyla hazırlanmıştır.', 1),
  ('Büyük Selçuklu Devleti', 'Kuruluş ve Anadolu Akınları', 'Büyük Selçuklu Devleti''nin resmen kurulmasını sağlayan savaş aşağıdakilerden hangisidir?', '["Pasinler","Dandanakan","Malazgirt","Miryokefalon","Yassıçemen"]', 1, '1040 Dandanakan Savaşı''ndan sonra Büyük Selçuklu Devleti resmen kurulmuştur.', 1),
  ('Büyük Selçuklu Devleti', 'Kuruluş ve Anadolu Akınları', '1048 Pasinler Savaşı''nın Türk tarihi açısından önemi aşağıdakilerden hangisidir?', '["Haçlılara karşı kazanılan ilk zafer olması","Bizans ile yapılan ilk savaş olması","Anadolu''nun kesin Türk yurdu olması","İstanbul''un fethedilmesi","Moğol ilerleyişinin durdurulması"]', 1, 'Pasinler Savaşı, Büyük Selçuklular ile Bizans arasında yapılan ilk savaştır.', 2),
  ('Büyük Selçuklu Devleti', 'Kuruluş ve Anadolu Akınları', 'Malazgirt Zaferi''nin Anadolu açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Bizans Devleti''nin tamamen yıkılması","Anadolu''nun Türkleşme sürecinin başlaması","Haçlı Seferleri''nin sona ermesi","İstanbul''un Osmanlılarca fethedilmesi","Anadolu''da siyasi birliğin sağlanması"]', 1, '1071 Malazgirt Zaferi ile Anadolu''nun kapıları Türklere açılmış; Türk beyliklerinin kurulması ve Türkleşme süreci hızlanmıştır.', 2),
  ('Büyük Selçuklu Devleti', 'Yönetim ve Kültür', 'Büyük Selçuklu Devleti''nde mali işlerden sorumlu divan aşağıdakilerden hangisidir?', '["Divan-ı Arz","Divan-ı İstifa","Divan-ı İnşa","Divan-ı İşraf","Divan-ı Mezalim"]', 1, 'Divan-ı İstifa, devletin mali işlerinden sorumludur.', 1),
  ('Büyük Selçuklu Devleti', 'Yönetim ve Kültür', 'Nizamiye Medreseleri''nin açılmasında aşağıdakilerden hangisi amaçlanmıştır?', '["Deniz ticaretini geliştirmek","Bâtınilik hareketine karşı Sünni düşünceyi güçlendirmek","Avrupa''daki derebeylikleri zayıflatmak","İpek Yolu''nu ele geçirmek","Yeniçeri Ocağına asker yetiştirmek"]', 1, 'Nizamiye Medreseleri eğitim-bilim faaliyetlerini geliştirmek ve Bâtınilik hareketine karşı Sünni düşünceyi güçlendirmek için açılmıştır.', 2),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Anadolu''ya İlk Akınlar ve Türkiye Adı', 'Türklerin Anadolu''ya ilk akınları aşağıdaki Türk topluluklarından hangisi tarafından gerçekleştirilmiştir?', '["Avrupa Hunları","Karahanlılar","Uygurlar","Hazarlar","Karluklar"]', 0, 'Türkler Anadolu''ya ilk akınlarını Avrupa Hunları döneminde gerçekleştirmiştir.', 1),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Anadolu''ya İlk Akınlar ve Türkiye Adı', 'Anadolu için Türkiye adının kullanılmaya başlanması aşağıdaki yüzyıllardan hangisine rastlar?', '["IX. yüzyıl","X. yüzyıl","XI. yüzyıl","XII. yüzyıl","XIII. yüzyıl"]', 3, 'Türkiye adı, XII. yüzyıldan itibaren Anadolu için kullanılmaya başlanmıştır.', 2),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Oğuz Göçlerinin Nedenleri', 'Aşağıdakilerden hangisi Oğuzların Anadolu''ya yönelmesinde etkili olan nedenlerden biri değildir?', '["Verimli toprakların bulunması","Uygun iklim koşulları","Bizans''ın zayıflaması","Gaza ve cihat anlayışı","Sanayi İnkılabı''nın yaşanması"]', 4, 'Sanayi İnkılabı çok daha sonraki bir dönemde gerçekleşmiştir; Oğuz göçlerinin nedeni değildir.', 1),
  ('Türklerin Anadolu''ya Yerleşme Süreci', 'Oğuz Göçlerinin Nedenleri', 'Oğuz göçlerinin Anadolu''nun tarihî yapısına en önemli etkisi aşağıdakilerden hangisidir?', '["Anadolu''da Roma kültürünün güçlenmesi","Anadolu''nun Türkleşme ve İslamlaşma sürecinin hızlanması","Haçlı devletlerinin kurulması","Bizans''ın Balkanlara yerleşmesi","Moğol istilalarının sona ermesi"]', 1, 'Oğuz göçleriyle Anadolu''da Türk nüfusu arttı; bölgenin Türkleşme ve İslamlaşma süreci hızlandı.', 2),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Anadolu''da Kurulan İlk Türk Beylikleri', 'Malazgirt Zaferi''nden sonra Anadolu''da kurulan ilk Türk beyliği aşağıdakilerden hangisidir?', '["Danişmentliler","Saltuklular","Artuklular","Mengücekliler","Çaka Beyliği"]', 1, 'Saltuklular, Malazgirt Zaferi''nden sonra Anadolu''da kurulan ilk Türk beyliği olarak kabul edilir.', 1),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Anadolu''da Kurulan İlk Türk Beylikleri', 'İlk Türk denizcisidir ve İzmir merkezli bir beylik kurarak ilk Türk donanmasını oluşturmuştur. Bu kişi aşağıdakilerden hangisidir?', '["Emir Danişment","İzzettin Keykavus","Çaka Bey","Saltuk Bey","Artuk Bey"]', 2, 'Çaka Bey, İzmir çevresinde ilk Türk denizciliğini başlatmış ve ilk Türk donanmasını kurmuştur.', 2),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Türkiye Selçuklu Devleti ve Miryokefalon', 'Türkiye Selçuklu Devleti''nin kurucusu aşağıdakilerden hangisidir?', '["Kutalmışoğlu Süleyman Şah","I. Kılıç Arslan","II. Kılıç Arslan","Alparslan","Melikşah"]', 0, 'Türkiye Selçuklu Devleti, Kutalmışoğlu Süleyman Şah tarafından İznik merkezli olarak kurulmuştur.', 1),
  ('Anadolu''nun İlk Siyasi Teşekkülleri', 'Türkiye Selçuklu Devleti ve Miryokefalon', '1176 Miryokefalon Savaşı''nın Türk tarihi açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Haçlı Seferlerinin başlaması","Anadolu''nun kesin Türk yurdu olduğunun anlaşılması","İstanbul''un fethedilmesi","Bizans''ın tamamen yıkılması","Moğol istilasının sona ermesi"]', 1, 'Miryokefalon Savaşı''ndan sonra Bizans''ın Anadolu''yu geri alma ümidi büyük ölçüde sona ermiştir.', 2),
  ('Hilal ve Haç Mücadelesi', 'Haçlı Seferleri ve Nedenleri', 'Haçlı Seferlerinin düzenlenmesinde aşağıdakilerden hangisinin etkili olduğu söylenemez?', '["Kudüs ve çevresindeki kutsal yerleri ele geçirme isteği","Ticaret yollarına hâkim olma düşüncesi","Doğu''nun zenginliklerine ulaşma arzusu","Avrupa''da topraksız şövalyelere yeni toprak bulma isteği","Osmanlı Devleti''ni Balkanlardan çıkarma düşüncesi"]', 4, 'Haçlı Seferleri Osmanlı Devleti kurulmadan önce başlamıştır. Bu nedenle Osmanlı''yı Balkanlardan çıkarma düşüncesi seferlerin nedeni değildir.', 2),
  ('Hilal ve Haç Mücadelesi', 'Haçlı Seferleri ve Nedenleri', 'I. Haçlı Seferi sonunda aşağıdaki devletlerden hangisi kurulmamıştır?', '["Urfa Kontluğu","Antakya Prensliği","Kudüs Krallığı","Trablus Kontluğu","Latin İmparatorluğu"]', 4, 'Latin İmparatorluğu IV. Haçlı Seferi sonrasında İstanbul''da kurulmuştur.', 2),
  ('Hilal ve Haç Mücadelesi', 'Sonraki Seferler ve Genel Sonuçlar', '1187 Hıttin Savaşı''nın ardından Kudüs''ü Haçlılardan geri alan hükümdar aşağıdakilerden hangisidir?', '["Nurettin Mahmut Zengi","Selahaddin Eyyubi","Kılıç Arslan","Alparslan","Baybars"]', 1, 'Hıttin Savaşı''nda Haçlıları yenen Selahaddin Eyyubi, Kudüs''ü geri almıştır.', 1),
  ('Hilal ve Haç Mücadelesi', 'Sonraki Seferler ve Genel Sonuçlar', 'IV. Haçlı Seferi''nin diğer Haçlı Seferlerinden farklı olarak en önemli sonucu aşağıdakilerden hangisidir?', '["Kudüs''ün Müslümanlardan alınması","İstanbul''un işgal edilerek Latin İmparatorluğu''nun kurulması","Anadolu''nun Türkleşmesinin sona ermesi","Moğolların Avrupa''ya ilerlemesi","Osmanlı Devleti''nin kurulması"]', 1, 'IV. Haçlı Seferi''nde Haçlılar hedeflerinden saparak İstanbul''u işgal etmiş ve Latin İmparatorluğu''nu kurmuştur.', 2),
  ('Moğol İstilası ve Anadolu', 'Yassıçemen, Baba İshak ve Kösedağ Savaşı', '1230 Yassıçemen Savaşı''nın Türkiye Selçuklu Devleti açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Anadolu Türk siyasi birliğinin sağlanması","Harzemşahların yıkılmasıyla Moğollarla komşu olunması","Haçlı Seferlerinin başlaması","Bizans''ın Anadolu''dan tamamen çıkarılması","Osmanlı Beyliği''nin kurulması"]', 1, 'Yassıçemen Savaşı sonunda Harzemşahlar yıkılmış, Türkiye Selçuklu Devleti Moğollarla komşu olmuştur.', 2),
  ('Moğol İstilası ve Anadolu', 'Yassıçemen, Baba İshak ve Kösedağ Savaşı', '1243 Kösedağ Savaşı''nın Anadolu''daki en önemli sonucu aşağıdakilerden hangisidir?', '["Türkiye Selçuklu Devleti''nin Bizans''a bağlanması","Anadolu''da Haçlı egemenliğinin başlaması","Türkiye Selçuklu Devleti''nin Moğol egemenliğine girmesi","Anadolu''da Türk beyliklerinin tamamen ortadan kalkması","İstanbul''un Osmanlılar tarafından fethedilmesi"]', 2, 'Kösedağ Savaşı''nda Moğollara yenilen Türkiye Selçuklu Devleti, Moğol egemenliği altına girmiştir.', 1),
  ('Moğol İstilası ve Anadolu', 'Yassıçemen, Baba İshak ve Kösedağ Savaşı', 'Baba İshak İsyanı''nın Türkiye Selçuklu Devleti üzerinde aşağıdaki etkilerden hangisine yol açtığı söylenebilir?', '["Devletin içten zayıflamasına","Anadolu''da siyasi birliğin güçlenmesine","Moğol tehlikesinin tamamen ortadan kalkmasına","Haçlı Seferlerinin sona ermesine","Denizcilik faaliyetlerinin artmasına"]', 0, 'Baba İshak İsyanı, devlet otoritesini zayıflatmış ve Kösedağ öncesinde Türkiye Selçuklu Devleti''ni içten sarsmıştır.', 2),
  ('Osmanlı Beyliği''nin Kuruluşu', 'Osman ve Orhan Gazi Dönemi', 'Osmanlı Beyliği''nin siyasi ve kurumsal olarak devletleşmesinin başlangıcı kabul edilen gelişme aşağıdakilerden hangisidir?', '["Bursa''nın fethedilmesi","Koyunhisar Savaşı''nın kazanılması","İznik''in alınması","Çimpe Kalesi''nin elde edilmesi","Ankara Savaşı''nın yapılması"]', 1, '1302 Koyunhisar Zaferi, Osmanlı hanedanının siyasi ve kurumsal olarak devletleşmesinin başlangıcı kabul edilir.', 2),
  ('Osmanlı Beyliği''nin Kuruluşu', 'Osman ve Orhan Gazi Dönemi', 'Orhan Gazi döneminde Bursa''nın fethedilmesinin Osmanlı Devleti açısından en önemli sonucu aşağıdakilerden hangisidir?', '["İlk donanmanın kurulması","Devlet merkezinin Bursa''ya taşınması","Rumeli''ye geçilmesi","İstanbul''un kuşatılması","Anadolu Türk birliğinin sağlanması"]', 1, 'Bursa 1326''da fethedildikten sonra Osmanlı Devleti''nin merkezi hâline gelmiştir.', 1),
  ('Osmanlı Beyliği''nin Kuruluşu', 'Osman ve Orhan Gazi Dönemi', '1329 Maltepe (Palekanon) Savaşı''nın Osmanlı Devleti''ne sağladığı kazanım aşağıdakilerden hangisidir?', '["Kocaeli çevresinde hâkimiyet kurması","Halifeliği alması","Balkanlara yerleşmesi","İstanbul''u fethetmesi","Anadolu beyliklerini tamamen ortadan kaldırması"]', 0, 'Maltepe Savaşı''ndan sonra Osmanlı Devleti Kocaeli bölgesinde hâkimiyet kurmuş, Bizans''ın Anadolu ile kara bağlantısı zayıflamıştır.', 2),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'Rumeli''ye Geçiş ve Çimpe Kalesi', 'Osmanlı Devleti''nin Rumeli''de elde ettiği ilk toprak parçası aşağıdakilerden hangisidir?', '["Gelibolu","Edirne","Çimpe Kalesi","Selanik","Sofya"]', 2, '1353''te elde edilen Çimpe Kalesi, Osmanlı Devleti''nin Rumeli''deki ilk toprağıdır.', 1),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'Rumeli''ye Geçiş ve Çimpe Kalesi', 'Osmanlı Devleti''nin Çimpe Kalesi''ni elde etmesinde aşağıdakilerden hangisi etkili olmuştur?', '["Haçlılarla yapılan savaş","Bizans''taki taht mücadelesinde Kantakuzen''e yardım edilmesi","Karesioğulları''nın yeniden kurulması","Ankara Savaşı''nın kazanılması","İstanbul''un fethedilmesi"]', 1, 'Orhan Bey, Bizans''taki taht mücadelesinde Kantakuzen''e yardım etmiş; karşılığında Çimpe Kalesi Osmanlılara verilmiştir.', 2),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'İskân ve İstimâlet Politikası', 'Osmanlı Devleti''nin fethedilen Rumeli topraklarına Türkmen nüfus yerleştirmesi aşağıdaki politikalardan hangisidir?', '["İltizam","İskân","Devşirme","Müsadere","Millet"]', 1, 'İskân politikası, fethedilen bölgelere Türkmen nüfus yerleştirerek kalıcı egemenlik kurmayı amaçlar.', 1),
  ('Osmanlı Devleti''nin Rumeli''de İskânı', 'İskân ve İstimâlet Politikası', 'Osmanlı Devleti''nin gayrimüslim halka din ve yaşam özgürlüğü tanıyarak yönetimine uyum sağlamaya çalışması aşağıdaki kavramlardan hangisiyle açıklanır?', '["Tımar","İstimâlet","Devşirme","Dirlik","İltizam"]', 1, 'İstimâlet politikası, hoşgörü ve gönül alma yoluyla fethedilen bölgelerde halkın Osmanlı yönetimine bağlılığını artırmayı amaçlamıştır.', 2),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Osmanlı''nın Beylikleri Katma Politikası', 'Osmanlı Devleti''ne katılan ilk Anadolu Türk beyliği aşağıdakilerden hangisidir?', '["Germiyanoğulları","Karesioğulları","Karamanoğulları","Aydınoğulları","Candaroğulları"]', 1, 'Karesioğulları, Osmanlı Devleti''ne katılan ilk Anadolu Türk beyliğidir.', 1),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Osmanlı''nın Beylikleri Katma Politikası', 'Karesioğulları''nın Osmanlı Devleti''ne katılmasının Rumeli fetihlerine katkısı aşağıdakilerden hangisidir?', '["Osmanlı''nın ilk donanmaya sahip olması","Halifeliğin Osmanlılara geçmesi","Yeniçeri Ocağı''nın kurulması","İstanbul''un fethedilmesi","Anadolu''nun kesin Türk yurdu olması"]', 0, 'Karesioğulları''nın denizcilik gücü Osmanlılara geçtiği için Osmanlı Devleti ilk donanmasına sahip olmuş ve Rumeli fetihleri kolaylaşmıştır.', 2),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Osmanlı''nın Beylikleri Katma Politikası', 'Osmanlı Devleti''nin Anadolu Türk siyasi birliğini sağlamak için kullandığı yöntemlerden biri değildir?', '["Evlilik","Satın alma","Diplomasi","Savaş","Sömürgecilik"]', 4, 'Osmanlı Devleti Anadolu Türk siyasi birliğini evlilik, satın alma, savaş ve diplomasi yoluyla sağlamaya çalışmıştır; sömürgecilik uygulamamıştır.', 2),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Ankara Savaşı ve Fetret Devri', '1402 Ankara Savaşı aşağıdaki devletlerden hangileri arasında yapılmıştır?', '["Osmanlı Devleti - Bizans Devleti","Osmanlı Devleti - Timur Devleti","Osmanlı Devleti - Memlük Devleti","Osmanlı Devleti - Safevi Devleti","Osmanlı Devleti - Karakoyunlu Devleti"]', 1, 'Ankara Savaşı, Yıldırım Bayezid ile Timur arasında gerçekleşmiştir.', 1),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Ankara Savaşı ve Fetret Devri', 'Ankara Savaşı''nın ardından yaklaşık on bir yıl süren taht mücadeleleri dönemi aşağıdakilerden hangisidir?', '["Lale Devri","Tanzimat Dönemi","Fetret Devri","Meşrutiyet Dönemi","Celâli İsyanları"]', 2, '1402-1413 yılları arasında yaşanan taht mücadeleleri Fetret Devri olarak adlandırılır.', 1),
  ('Anadolu''da Türk Siyasi Birliğini Sağlama', 'Ankara Savaşı ve Fetret Devri', 'Fetret Devri''ne son vererek Osmanlı Devleti''nde merkezî otoriteyi yeniden sağlayan hükümdar aşağıdakilerden hangisidir?', '["I. Murat","Yıldırım Bayezid","Çelebi Mehmet","II. Murat","Fatih Sultan Mehmet"]', 2, 'Çelebi Mehmet, Fetret Devri''ne son verdiği ve devleti toparladığı için Osmanlı Devleti''nin ikinci kurucusu kabul edilir.', 2),
  ('Savaşçılar ve Askerler', 'Tımar Sistemi ve Tımarlı Sipahiler', 'Tımar sisteminde toprağın mülkiyeti genel olarak kime aittir?', '["Tımarlı sipahiye","Köylüye","Devlete","Esnafa","Vakıflara"]', 2, 'Tımar sisteminde tarım arazilerinin mülkiyeti devlete aittir; sipahilere ise hizmet karşılığı vergi toplama yetkisi verilir.', 1),
  ('Savaşçılar ve Askerler', 'Tımar Sistemi ve Tımarlı Sipahiler', 'Aşağıdakilerden hangisi tımarlı sipahilerin görevlerinden biri değildir?', '["Taşrada güvenliği sağlamak","Sefer zamanında orduya katılmak","Cebelü yetiştirmek","Vergilerin tahsil edilmesini sağlamak","Divan-ı Hümayun''a başkanlık etmek"]', 4, 'Divan-ı Hümayun''a sadrazam başkanlık ederdi. Tımarlı sipahiler taşrada görev yapar, cebelü yetiştirir ve seferlerde orduya katılırdı.', 2),
  ('Savaşçılar ve Askerler', 'Tımar Sistemi ve Tımarlı Sipahiler', 'Tımar sisteminin Osmanlı Devleti''ne sağladığı en önemli yararlardan biri aşağıdakilerden hangisidir?', '["Hazineye yük olmadan asker yetiştirmek","Deniz ticaretini geliştirmek","Medrese sayısını artırmak","Kapitülasyonları kaldırmak","Avrupa''da sömürge kurmak"]', 0, 'Tımar sistemi sayesinde Osmanlı Devleti, merkez hazinesinden doğrudan harcama yapmadan eyalet askerleri yetiştirmiştir.', 2),
  ('Savaşçılar ve Askerler', 'Kapıkulu Ocakları ve Devşirme', 'Osmanlı Devleti''nin maaşlı ve sürekli merkez ordusunu oluşturan askerî teşkilat aşağıdakilerden hangisidir?', '["Tımarlı Sipahiler","Akıncılar","Kapıkulu Ocakları","Azaplar","Yaya ve Müsellemler"]', 2, 'Kapıkulu Ocakları, Osmanlı Devleti''nin maaşlı ve sürekli merkez ordusudur.', 1),
  ('Savaşçılar ve Askerler', 'Kapıkulu Ocakları ve Devşirme', 'Yeniçerilerin üç ayda bir aldığı maaşa ne ad verilir?', '["Cülus","Ulufe","Cizye","Haraç","Avarız"]', 1, 'Kapıkulu askerlerine ve yeniçerilere üç ayda bir ulufe adı verilen maaş ödenirdi.', 1),
  ('Savaşçılar ve Askerler', 'Kapıkulu Ocakları ve Devşirme', 'Pençik sisteminde savaş esirlerinin ne kadarı devlet hizmetine alınırdı?', '["Onda biri","Beşte biri","Dörtte biri","Yarısı","Üçte biri"]', 1, 'Pençik, beşte bir anlamına gelir; savaş esirlerinin beşte biri devlet hizmeti için ayrılırdı.', 2),
  ('Sosyal ve Kültürel Faaliyetler', 'Osmanlı''da Yönetici Sınıflar (Askerî)', 'Osmanlı Devleti''nde yöneten ve vergiden muaf olan sınıfa ne ad verilirdi?', '["Reaya","Askerî","Ayan","Lonca","Vakıf"]', 1, 'Osmanlı toplumunda yöneten ve vergiden muaf kesim askerî, vergi veren halk ise reaya olarak adlandırılırdı.', 1),
  ('Sosyal ve Kültürel Faaliyetler', 'Osmanlı''da Yönetici Sınıflar (Askerî)', 'Aşağıdakilerden hangisi Osmanlı yönetici sınıflarından ilmiye grubunda yer alır?', '["Defterdar","Nişancı","Kazasker","Kaptan-ı derya","Subaşı"]', 2, 'Kazasker; eğitim, hukuk ve adalet işleriyle ilgilenen ilmiye sınıfında yer alırdı.', 2),
  ('Sosyal ve Kültürel Faaliyetler', 'Osmanlı''da Yönetici Sınıflar (Askerî)', 'Osmanlı Devleti''nde maliye ve yazışma işlerinden sorumlu yönetici sınıf aşağıdakilerden hangisidir?', '["Seyfiye","İlmiye","Kalemiye","Reaya","Lonca"]', 2, 'Kalemiye sınıfı, devletin maliye ve yazışma işlerini yürütürdü.', 1),
  ('Sosyal ve Kültürel Faaliyetler', 'Mutasavvıflar ve Bilim İnsanları', 'Ahilik teşkilatını kurarak esnaf arasında dayanışma ve meslek ahlakını geliştiren kişi aşağıdakilerden hangisidir?', '["Ahi Evran","Akşemseddin","Ali Kuşçu","Hacı Bayram Veli","Nizamülmülk"]', 0, 'Ahi Evran, Ahilik teşkilatının kurucusu kabul edilir.', 1),
  ('Sosyal ve Kültürel Faaliyetler', 'Mutasavvıflar ve Bilim İnsanları', 'Hastalıkların gözle görülmeyen canlılar yoluyla bulaşabileceğini belirten fikirleriyle tanınan bilim insanı aşağıdakilerden hangisidir?', '["Ali Kuşçu","Akşemseddin","İbn Sina","Farabi","Piri Reis"]', 1, 'Akşemseddin, hastalıkların mikroplar yoluyla bulaşabileceğine ilişkin fikirleriyle tanınır.', 2),
  ('Sosyal ve Kültürel Faaliyetler', 'Mutasavvıflar ve Bilim İnsanları', 'Astronomi ve matematik alanındaki çalışmalarıyla tanınan Türk-İslam bilim insanı aşağıdakilerden hangisidir?', '["Ali Kuşçu","Ahi Evran","Akşemseddin","Şeyh Edebali","Hacı Bektaş Veli"]', 0, 'Ali Kuşçu astronomi ve matematik alanında önemli çalışmalar yapmıştır.', 1),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Nedenleri ve Hazırlıklar', 'Fatih Sultan Mehmet''in İstanbul''un fethi öncesinde Rumeli Hisarı''nı yaptırmasının temel amacı aşağıdakilerden hangisidir?', '["Anadolu Türk birliğini sağlamak","Boğazdan gelebilecek yardımları denetlemek","Haçlı Seferlerini başlatmak","Balkanlarda iskân yapmak","Memlük Devleti''ni yıkmak"]', 1, 'Rumeli Hisarı, Bizans''a Karadeniz üzerinden gelebilecek yardımları engellemek ve Boğazı denetlemek için yaptırılmıştır.', 2),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Nedenleri ve Hazırlıklar', 'Aşağıdakilerden hangisi İstanbul''un fethi için yapılan hazırlıklardan biri değildir?', '["Şahi toplarının döktürülmesi","Güçlü donanma hazırlanması","Rumeli Hisarı''nın yapılması","Anadolu Hisarı''nın yıkılması","Gemilerin karadan yürütülmesi"]', 3, 'Anadolu Hisarı yıkılmamış, Boğaz denetimini güçlendirmek için Rumeli Hisarı yaptırılmıştır.', 2),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Dünya Tarihine Etkisi', 'İstanbul''un fethiyle yıkılan devlet aşağıdakilerden hangisidir?', '["Doğu Roma (Bizans) Devleti","Latin İmparatorluğu","Kutsal Roma Germen İmparatorluğu","Memlük Devleti","Trabzon Rum Devleti"]', 0, '1453 İstanbul''un Fethi ile Doğu Roma yani Bizans Devleti sona ermiştir.', 1),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Dünya Tarihine Etkisi', 'İstanbul''un fethinin Avrupa''da derebeylik sisteminin zayıflamasına katkı sağlamasının temel nedeni aşağıdakilerden hangisidir?', '["Bizans''ın güçlenmesi","Topların surları yıkabileceğinin anlaşılması","İpek Yolu''nun kapanması","Haçlı Seferlerinin bitmesi","Reform hareketlerinin başlaması"]', 1, 'Büyük topların surları yıkabileceğinin anlaşılması, şatolara dayalı derebeylik düzenini zayıflatmıştır.', 2),
  ('İstanbul''un Fethi ve Sonuçları', 'Fethin Dünya Tarihine Etkisi', 'İstanbul''un fethinden sonra bazı Bizanslı bilim insanlarının İtalya''ya gitmesi hangi gelişmeyi hızlandırmıştır?', '["Reform","Rönesans","Sanayi İnkılabı","Fransız İhtilali","Coğrafi Keşifler"]', 1, 'Bizanslı bilim insanlarının İtalya''ya gitmesi, Antik Yunan-Roma kültürünün yeniden canlanmasına ve Rönesans''ın hızlanmasına katkı sağlamıştır.', 2),
  ('İslam Dünyasında Birliği Sağlama', 'Safevi ve Memluk Mücadelesi (Yavuz Dönemi)', 'Yavuz Sultan Selim''in Safevilerle yaptığı ve Safevi tehlikesini büyük ölçüde azalttığı savaş aşağıdakilerden hangisidir?', '["Mohaç","Çaldıran","Mercidabık","Ridaniye","Otlukbeli"]', 1, '1514 Çaldıran Savaşı ile Safevi tehlikesi büyük ölçüde azaltılmıştır.', 1),
  ('İslam Dünyasında Birliği Sağlama', 'Safevi ve Memluk Mücadelesi (Yavuz Dönemi)', 'Memlük Devleti''nin yıkılmasını sağlayan savaş aşağıdakilerden hangisidir?', '["Çaldıran","Ridaniye","Mohacs","Varna","Nikopolis"]', 1, '1517 Ridaniye Savaşı sonrasında Memlük Devleti yıkılmıştır.', 1),
  ('İslam Dünyasında Birliği Sağlama', 'Safevi ve Memluk Mücadelesi (Yavuz Dönemi)', 'Yavuz Sultan Selim döneminde aşağıdakilerden hangisinin Osmanlı topraklarına katılmasıyla Osmanlı Devleti İslam dünyasında daha güçlü bir konuma ulaşmıştır?', '["Kırım ve Kafkasya","Suriye, Mısır ve Hicaz","Mora ve Girit","Macaristan ve Avusturya","İran ve Irak"]', 1, 'Memlüklerin yıkılmasıyla Suriye, Mısır ve Hicaz Osmanlı topraklarına katılmış; Osmanlı''nın İslam dünyasındaki etkisi artmıştır.', 2),
  ('Dünyanın Muhteşem Gücü Osmanlı', 'Kanuni Sultan Süleyman Dönemi', 'Kanuni Sultan Süleyman döneminde Macaristan Krallığı''nın büyük ölçüde Osmanlı hâkimiyetine girmesini sağlayan savaş aşağıdakilerden hangisidir?', '["Mohaç","Mercidabık","Çaldıran","Varna","II. Kosova"]', 0, '1526 Mohaç Meydan Muharebesi''nden sonra Macaristan Krallığı büyük ölçüde Osmanlı hâkimiyetine girmiştir.', 1),
  ('Dünyanın Muhteşem Gücü Osmanlı', 'Kanuni Sultan Süleyman Dönemi', '1533 İstanbul Antlaşması''nın Osmanlı Devleti açısından önemi aşağıdakilerden hangisidir?', '["Rusya''nın Karadeniz''e inmesini engellemesi","Avusturya''nın Osmanlı siyasi üstünlüğünü kabul etmesi","Fransa''ya kapitülasyon verilmesi","Memlük Devleti''nin yıkılması","İran ile sınır sorununun çözülmesi"]', 1, '1533 İstanbul Antlaşması ile Avusturya arşidükü Osmanlı sadrazamına denk sayılmış, Osmanlı''nın siyasi üstünlüğü kabul edilmiştir.', 2),
  ('Dünyanın Muhteşem Gücü Osmanlı', 'Kanuni Sultan Süleyman Dönemi', 'Kanuni Sultan Süleyman''ın çıktığı son sefer aşağıdakilerden hangisidir?', '["Belgrad Seferi","Rodos Seferi","Zigetvar Seferi","Mohaç Seferi","İran Seferi"]', 2, 'Kanuni Sultan Süleyman''ın son seferi Zigetvar Seferi''dir.', 1),
  ('Stratejik Siyaset ve Dünya Gücü', 'Kapitülasyonlar', 'Kanuni Sultan Süleyman''ın Fransa''ya kapitülasyon vermesindeki temel amaç aşağıdakilerden hangisidir?', '["Osmanlı ekonomisini zayıflatmak","Avrupa''daki Habsburg baskısını dengelemek","İran ile ittifak kurmak","Yeniçeri Ocağını güçlendirmek","Memlük Devleti''ni desteklemek"]', 1, 'Kanuni, Fransa''ya kapitülasyon vererek Habsburglara karşı Avrupa''daki siyasi dengeyi Osmanlı lehine çevirmeyi amaçlamıştır.', 2),
  ('Stratejik Siyaset ve Dünya Gücü', 'Kapitülasyonlar', 'Kapitülasyonların sürekli hâle gelmesi aşağıdaki yıllardan hangisinde gerçekleşmiştir?', '["1533","1606","1699","1740","1774"]', 3, 'Fransa''ya verilen kapitülasyonlar 1740 yılında sürekli hâle getirilmiştir.', 1),
  ('Stratejik Siyaset ve Dünya Gücü', 'Kapitülasyonlar', 'Kapitülasyonların Osmanlı Devleti üzerindeki uzun vadeli etkisi aşağıdakilerden hangisidir?', '["Merkezî otoritenin güçlenmesi","Yerli üreticinin Avrupa mallarıyla rekabetinin zorlaşması","Tımar sisteminin yaygınlaşması","Avrupa''daki toprakların genişlemesi","Devşirme sisteminin kaldırılması"]', 1, 'Kapitülasyonlar zamanla yabancıların ekonomik üstünlük kazanmasına ve Osmanlı ekonomisinin olumsuz etkilenmesine yol açmıştır.', 2),
  ('Stratejik Siyaset ve Dünya Gücü', 'Hint Deniz Seferleri', 'Osmanlı Devleti''nin Hint Deniz Seferleri düzenlemesinin temel amacı aşağıdakilerden hangisidir?', '["Bizans''ı yeniden kurmak","Baharat Yolu''nu canlandırıp Portekiz üstünlüğünü kırmak","Akdeniz''deki Venedik gücünü bitirmek","Rusya''nın güneye inmesini engellemek","Anadolu Türk birliğini sağlamak"]', 1, 'Osmanlı Devleti, Portekiz''in Hint Okyanusu ve Baharat Yolu üzerindeki etkisini kırmak için Hint Deniz Seferleri düzenlemiştir.', 1),
  ('Stratejik Siyaset ve Dünya Gücü', 'Hint Deniz Seferleri', 'Hint Deniz Seferlerinde kesin başarı sağlanamamasında aşağıdakilerden hangisinin etkili olduğu söylenemez?', '["Osmanlı gemilerinin açık deniz şartlarına yeterince uygun olmaması","Bölge halkından yeterli destek alınamaması","Portekiz donanmasının güçlü olması","Osmanlı''nın güçlü okyanus filosuna sahip olması","Sefer alanının merkeze uzak olması"]', 3, 'Osmanlı''nın güçlü bir okyanus filosu yoktu; bu nedenle açık deniz şartları ve teknik yetersizlikler seferleri zorlaştırmıştır.', 2),
  ('Stratejik Siyaset ve Dünya Gücü', 'Hint Deniz Seferleri', 'Hint Deniz Seferleri sonucunda Osmanlı Devleti''nin güvenliğini güçlendirdiği deniz alanları aşağıdakilerden hangisidir?', '["Karadeniz ve Ege Denizi","Kızıldeniz ve Basra Körfezi","Atlas Okyanusu ve Akdeniz","Hazar Denizi ve Aral Gölü","Manş Denizi ve Baltık Denizi"]', 1, 'Seferler kesin başarıya ulaşmasa da Kızıldeniz ve Basra Körfezi''nin güvenliği güçlendirilmiştir.', 2),
  ('Saray ve Şehir Kültürü', 'Saray Teşkilatı', 'Osmanlı sarayında devşirme kökenli öğrencilerin eğitim görerek devlet adamı olarak yetiştirildiği bölüm aşağıdakilerden hangisidir?', '["Birun","Enderun","Harem","Divan-ı Hümayun","Şehzadegan Dairesi"]', 1, 'Enderun, Osmanlı Devleti''nde üst düzey devlet adamı yetiştiren saray eğitim kurumudur.', 1),
  ('Saray ve Şehir Kültürü', 'Saray Teşkilatı', 'Padişahın ailesiyle birlikte yaşadığı özel saray bölümü aşağıdakilerden hangisidir?', '["Birun","Enderun","Harem","Divanhane","Bâbıâli"]', 2, 'Harem, padişahın ve ailesinin yaşadığı özel bölümdür.', 1),
  ('Saray ve Şehir Kültürü', 'Saray Teşkilatı', 'Aşağıdakilerden hangisi Osmanlı sarayının ana bölümlerinden biri değildir?', '["Birun","Enderun","Harem","Nizamiye","—"]', 3, 'Osmanlı sarayı Birun, Enderun ve Harem olmak üzere üç ana bölümden oluşurdu. Nizamiye ise Büyük Selçuklu Devleti dönemindeki medrese sistemidir.', 2),
  ('Saray ve Şehir Kültürü', 'Divan-ı Hümayun', 'Fatih Sultan Mehmet döneminden itibaren Divan-ı Hümayun''a kim başkanlık etmeye başlamıştır?', '["Padişah","Kazasker","Nişancı","Sadrazam","Defterdar"]', 3, 'Fatih Sultan Mehmet''ten itibaren Divan-ı Hümayun''a sadrazam başkanlık etmeye başlamıştır.', 1),
  ('Saray ve Şehir Kültürü', 'Divan-ı Hümayun', 'Divan-ı Hümayun''da devletin mali işlerinden sorumlu görevli aşağıdakilerden hangisidir?', '["Nişancı","Kazasker","Defterdar","Reisülküttap","Kaptan-ı derya"]', 2, 'Defterdar, Osmanlı Devleti''nde maliye işlerinden sorumluydu.', 1),
  ('Saray ve Şehir Kültürü', 'Divan-ı Hümayun', 'Divan-ı Hümayun''da devlet yazışmaları ve tapu işlerinden sorumlu görevli aşağıdakilerden hangisidir?', '["Nişancı","Kazasker","Defterdar","Sadrazam","Şeyhülislam"]', 0, 'Nişancı, devlet yazışmalarını yürütür ve tapu-tahrir işlerinden sorumlu olurdu.', 2),
  ('Saray ve Şehir Kültürü', 'Gelenekler Işığında Devlet İdaresi', 'Fatih Sultan Mehmet''in merkezi otoriteyi güçlendirmek amacıyla hazırlattığı hukuk düzenlemelerine ne ad verilir?', '["Ferman","Kanunname","Menşur","Adaletname","Fetva"]', 1, 'Fatih Kanunnamesi, devlet teşkilatını ve bazı yönetim ilkelerini düzenleyen önemli bir hukuk metnidir.', 1),
  ('Saray ve Şehir Kültürü', 'Gelenekler Işığında Devlet İdaresi', 'I. Ahmet döneminde kabul edilen, hanedanın en yaşlı üyesinin tahta geçmesini esas alan sistem aşağıdakilerden hangisidir?', '["Pençik","Devşirme","Ekber ve Erşed","Tımar","Müsadere"]', 2, 'Ekber ve Erşed Sistemi, taht kavgalarını azaltmak amacıyla hanedanın en yaşlı üyesinin padişah olmasını öngörmüştür.', 1),
  ('Saray ve Şehir Kültürü', 'Gelenekler Işığında Devlet İdaresi', 'Ekber ve Erşed Sistemi''nin uygulanmaya başlamasıyla aşağıdakilerden hangisi yaygınlaşmıştır?', '["Şehzadelerin sancağa çıkması","Kafes usulü","İkili teşkilat","Tımar sistemi","Devşirme uygulaması"]', 1, 'Şehzadelerin sancağa çıkma uygulaması kaldırılmış, bunun yerine kafes usulü yaygınlaşmıştır.', 2),
  ('Millet Sistemi', 'Osmanlı Millet Sistemi', 'Osmanlı Devleti''nde millet sistemi temel olarak hangi ölçüte göre oluşturulmuştur?', '["Etnik köken","Dil","Coğrafi bölge","Din ve mezhep","Meslek grubu"]', 3, 'Osmanlı millet sistemi etnik kökene değil, din ve mezhep esasına dayanıyordu.', 1),
  ('Millet Sistemi', 'Osmanlı Millet Sistemi', 'Millet sistemi kapsamında gayrimüslim topluluklara tanınan haklardan biri aşağıdakilerden hangisidir?', '["Kendi dinî ve eğitim işlerini yürütme","Devletin başına geçme","Askerlikten tamamen bağımsız devlet kurma","Miri toprakları mülk edinme","Padişah seçme"]', 0, 'Gayrimüslimler kendi dinî, hukuki ve eğitim işlerinde belirli ölçüde serbest bırakılmıştır.', 2),
  ('Millet Sistemi', 'Osmanlı Millet Sistemi', 'Gayrimüslimlerden askerlik hizmeti karşılığı alınan vergi aşağıdakilerden hangisidir?', '["Aşar","Cizye","Öşür","Avârız","Haraç"]', 1, 'Cizye, Osmanlı Devleti''nde gayrimüslim erkeklerden alınan baş vergisidir.', 1),
  ('Toprak Sistemi ve Lonca', 'Osmanlı Toprak Sistemi', 'Osmanlı Devleti''nde mülkiyeti devlete ait olan topraklara ne ad verilir?', '["Mülk","Vakıf","Miri","Mukataa","Arpalık"]', 2, 'Miri arazi, mülkiyeti devlete ait olan Osmanlı topraklarıdır.', 1),
  ('Toprak Sistemi ve Lonca', 'Osmanlı Toprak Sistemi', 'Miri arazilerin gelirine göre has, zeamet ve tımar şeklinde ayrılması aşağıdaki sistemlerden hangisiyle ilgilidir?', '["Millet sistemi","Dirlik sistemi","Devşirme sistemi","Lonca sistemi","Malikâne sistemi"]', 1, 'Dirlik sistemi, devlet arazilerinin gelirlerinin has, zeamet ve tımar olarak dağıtılmasına dayanır.', 2),
  ('Toprak Sistemi ve Lonca', 'Osmanlı Toprak Sistemi', 'Aşağıdakilerden hangisi Osmanlı Devleti''ndeki temel toprak türlerinden biridir?', '["Feodal arazi","Miri arazi","Sömürge arazisi","Senyör arazisi","Manor sistemi"]', 1, 'Osmanlı toprak sistemi miri, mülk ve vakıf arazileri olmak üzere temel sınıflara ayrılırdı.', 1),
  ('Toprak Sistemi ve Lonca', 'Lonca Teşkilatı ve Narh', 'Osmanlı Devleti''nde esnaf ve zanaatkârların meslek düzenini sağlayan teşkilat aşağıdakilerden hangisidir?', '["Enderun","Lonca","Divan-ı Hümayun","Medrese","Tımar"]', 1, 'Lonca teşkilatı esnaf ve zanaatkârların üretim, kalite ve meslek düzenini sağlayan örgüttür.', 1),
  ('Toprak Sistemi ve Lonca', 'Lonca Teşkilatı ve Narh', 'Temel ihtiyaç maddelerinin fiyatlarının devlet tarafından denetlenmesine ne ad verilir?', '["Gedik","Narh","Müsadere","İltizam","İstimâlet"]', 1, 'Narh uygulamasıyla temel ihtiyaç maddelerinin en yüksek ve en düşük satış fiyatları devlet tarafından belirlenirdi.', 1),
  ('Toprak Sistemi ve Lonca', 'Lonca Teşkilatı ve Narh', 'Osmanlı Devleti''nde bir mesleği yapma hakkını düzenleyen uygulama aşağıdakilerden hangisidir?', '["Gedik","Cizye","Mukataa","Cülus","Müsadere"]', 0, 'Gedik sistemi, bir iş veya mesleği yapma hakkının düzenlenmesine dayanırdı.', 2),
  ('Uzun Savaşlardan Diplomasiye', 'Zitvatorok ve Bucaş Antlaşmaları', '1606 Zitvatorok Antlaşması''nın Osmanlı Devleti açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Avusturya''nın Osmanlı''ya bağlanması","Avusturya arşidükünün Osmanlı padişahına denk kabul edilmesi","Macaristan''ın tamamen Osmanlı topraklarına katılması","Rusya''nın Karadeniz''e inmesi","Fransa''ya kapitülasyon verilmesi"]', 1, 'Zitvatorok Antlaşması ile Avusturya arşidükü Osmanlı padişahına denk kabul edilmiş, Osmanlı Devleti Avrupa diplomasisinde prestij kaybetmiştir.', 2),
  ('Uzun Savaşlardan Diplomasiye', 'Zitvatorok ve Bucaş Antlaşmaları', 'Bucaş Antlaşması ile Osmanlı Devleti''nin hâkimiyetine giren bölge aşağıdakilerden hangisidir?', '["Kırım","Podolya","Mora","Azak","Erdel"]', 1, '1672 Bucaş Antlaşması ile Podolya Osmanlı Devleti''nin hâkimiyetine girmiştir.', 1),
  ('Uzun Savaşlardan Diplomasiye', 'Zitvatorok ve Bucaş Antlaşmaları', 'Bucaş Antlaşması''nın Osmanlı tarihi açısından önemi aşağıdakilerden hangisidir?', '["Osmanlı''nın Avrupa''da ilk kez toprak kaybetmesi","Batıda toprak kazandığı son antlaşma olması","Rusya''ya Boğazlardan geçiş hakkı vermesi","Avusturya karşısında siyasi üstünlüğünü kaybetmesi","Kırım''ın bağımsız olması"]', 1, 'Bucaş Antlaşması, Osmanlı Devleti''nin batıda toprak kazandığı son antlaşmadır.', 2),
  ('Uzun Savaşlardan Diplomasiye', 'Karlofça ve 1700 İstanbul Antlaşması', '1699 Karlofça Antlaşması''nın Osmanlı Devleti açısından en önemli sonucu aşağıdakilerden hangisidir?', '["İlk kez geniş çaplı toprak kaybetmesi","İstanbul''un fethedilmesi","Avrupa''da yeniden üstünlük kurması","Kırım''ı geri alması","Anadolu Türk birliğini sağlaması"]', 0, 'Karlofça Antlaşması ile Osmanlı Devleti Avrupa''da ilk büyük toprak kaybını yaşamış ve savunma dönemine girmiştir.', 1),
  ('Uzun Savaşlardan Diplomasiye', 'Karlofça ve 1700 İstanbul Antlaşması', 'Karlofça Antlaşması ile Mora aşağıdaki devletlerden hangisine bırakılmıştır?', '["Rusya","Avusturya","Lehistan","Venedik","Fransa"]', 3, 'Karlofça Antlaşması ile Mora Venedik''e bırakılmıştır.', 2),
  ('Uzun Savaşlardan Diplomasiye', 'Karlofça ve 1700 İstanbul Antlaşması', '1700 İstanbul Antlaşması ile Osmanlı Devleti''nin Rusya''ya bıraktığı yer aşağıdakilerden hangisidir?', '["Belgrad","Azak Kalesi","Podolya","Kırım","Mora"]', 1, '1700 İstanbul Antlaşması ile Azak Kalesi Rusya''ya bırakılmıştır.', 1),
  ('Okyanusların Önem Kazanması', 'Coğrafi Keşifler ve Kadırgadan Kalyona Geçiş', 'Coğrafi Keşiflerin Osmanlı Devleti üzerindeki en önemli ekonomik etkisi aşağıdakilerden hangisidir?', '["İpek ve Baharat yollarının yeniden canlanması","Gümrük ve liman gelirlerinin azalması","Tarım üretiminin artması","Avrupa''daki toprakların genişlemesi","Tımar sisteminin güçlenmesi"]', 1, 'Ticaret yollarının Atlas Okyanusu kıyılarına kayması, Osmanlı''nın İpek ve Baharat yollarından elde ettiği gümrük ve liman gelirlerini azaltmıştır.', 2),
  ('Okyanusların Önem Kazanması', 'Coğrafi Keşifler ve Kadırgadan Kalyona Geçiş', 'Deniz savaşlarının okyanuslara taşınmasıyla Osmanlı Devleti''nin kullanmaya yöneldiği yelkenli ve çok toplu savaş gemisi aşağıdakilerden hangisidir?', '["Kadırga","Kalyon","Şayka","Firkateyn","Çektiri"]', 1, 'Kalyonlar, açık deniz ve okyanus şartlarında kadırgalara göre daha dayanıklı ve daha fazla top taşıyabilen yelkenli savaş gemileridir.', 1),
  ('Okyanusların Önem Kazanması', 'Coğrafi Keşifler ve Kadırgadan Kalyona Geçiş', 'Aşağıdakilerden hangisi Coğrafi Keşiflerin sonuçlarından biri değildir?', '["Akdeniz limanlarının önem kaybetmesi","Atlas Okyanusu kıyısındaki limanların gelişmesi","Avrupa''nın ekonomik olarak güçlenmesi","İpek Yolu''nun eski önemine kavuşması","Osmanlı ekonomisinin olumsuz etkilenmesi"]', 3, 'Coğrafi Keşiflerden sonra İpek Yolu eski önemini kazanmadı; aksine yeni deniz yolları nedeniyle önem kaybetti.', 2),
  ('Fetihlerden Savunmaya', 'Prut ve Pasarofça Antlaşmaları', '1711 Prut Antlaşması Osmanlı Devleti ile aşağıdaki devletlerden hangisi arasında imzalanmıştır?', '["Avusturya","Rusya","Lehistan","Venedik","İran"]', 1, 'Prut Antlaşması, Osmanlı Devleti ile Rusya arasında imzalanmıştır.', 1),
  ('Fetihlerden Savunmaya', 'Prut ve Pasarofça Antlaşmaları', '1718 Pasarofça Antlaşması''nın Osmanlı Devleti açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Avrupa karşısında fetih siyasetine yeniden dönmesi","Savunma ve ıslahat siyasetine yönelmesi","Halifeliğin Osmanlılara geçmesi","Kırım''ın geri alınması","İstanbul''un fethedilmesi"]', 1, 'Pasarofça Antlaşması sonrasında Osmanlı Devleti Avrupa karşısında fetih politikasını büyük ölçüde bırakmış, savunma ve ıslahat anlayışına yönelmiştir.', 2),
  ('Fetihlerden Savunmaya', 'Prut ve Pasarofça Antlaşmaları', 'Pasarofça Antlaşması ile Osmanlı Devleti''nin Avusturya''ya bıraktığı önemli şehir aşağıdakilerden hangisidir?', '["Edirne","Bursa","Belgrad","İznik","Konya"]', 2, '1718 Pasarofça Antlaşması ile Belgrad ve çevresi Avusturya''ya bırakılmıştır.', 1),
  ('Fetihlerden Savunmaya', 'Belgrad ve Küçük Kaynarca Antlaşmaları', '1739 Belgrad Antlaşması ile aşağıdaki yerlerden hangisi yeniden Osmanlı Devleti''ne katılmıştır?', '["Azak","Belgrad","Kırım","Podolya","Mora"]', 1, '1739 Belgrad Antlaşması ile Belgrad ve Semendire yeniden Osmanlı topraklarına katılmıştır.', 1),
  ('Fetihlerden Savunmaya', 'Belgrad ve Küçük Kaynarca Antlaşmaları', 'Küçük Kaynarca Antlaşması ile bağımsız hâle getirilen ve daha sonra Rusya tarafından işgal edilen bölge aşağıdakilerden hangisidir?', '["Kırım","Mora","Girit","Podolya","Erdel"]', 0, 'Küçük Kaynarca Antlaşması ile Kırım bağımsız hâle getirildi; bu durum Rusya''nın Kırım üzerinde etkili olmasını kolaylaştırdı.', 1),
  ('Fetihlerden Savunmaya', 'Belgrad ve Küçük Kaynarca Antlaşmaları', 'Küçük Kaynarca Antlaşması''nın Rusya açısından en önemli sonuçlarından biri aşağıdakilerden hangisidir?', '["Akdeniz''deki tüm adaları ele geçirmesi","Karadeniz''de güç kazanması","İstanbul''u işgal etmesi","Osmanlı halifesini tanıması","Avusturya''yı yenmesi"]', 1, 'Küçük Kaynarca Antlaşması ile Rusya Karadeniz''de güç kazanmış ve Osmanlı Devleti''nin iç işlerine karışma fırsatı elde etmiştir.', 2),
  ('Avrupa''da Değişim Çağı', 'Rönesans, Reform ve Vestfalya', 'Rönesans hareketleri ilk olarak aşağıdaki ülkelerden hangisinde başlamıştır?', '["İspanya","İtalya","Fransa","İngiltere","Almanya"]', 1, 'Rönesans, şehirleşme ve ticaretin geliştiği İtalya''da başlamıştır.', 1),
  ('Avrupa''da Değişim Çağı', 'Rönesans, Reform ve Vestfalya', 'Reform hareketlerinin Avrupa''daki en belirgin sonucu aşağıdakilerden hangisidir?', '["Katolik Kilisesi''nin otoritesinin zayıflaması","Feodalitenin yeniden güçlenmesi","Haçlı Seferlerinin başlaması","İpek Yolu''nun canlanması","Mutlak monarşilerin tamamen ortadan kalkması"]', 0, 'Reform hareketleri Katolik Kilisesi''nin dinî ve siyasi otoritesini zayıflatmıştır.', 2),
  ('Avrupa''da Değişim Çağı', 'Rönesans, Reform ve Vestfalya', '1648 Vestfalya Antlaşması''nın Avrupa tarihi açısından önemi aşağıdakilerden hangisidir?', '["Fransız İhtilali''ni başlatması","Coğrafi Keşifleri bitirmesi","Din savaşlarını sona erdirip modern devletler hukukuna zemin hazırlaması","Osmanlı Devleti''ni Avrupa''nın en güçlü devleti yapması","Amerika''nın keşfedilmesini sağlaması"]', 2, 'Vestfalya Antlaşması, Avrupa''daki din savaşlarını sona erdirmiş ve modern devletler hukukuyla ulus devlet anlayışının gelişmesine katkı sağlamıştır.', 2),
  ('Avrupa''da Değişim Çağı', 'Bilim Devrimi ve Aydınlanma', 'Güneş merkezli evren modelini savunarak Bilim Devrimi''ne katkı sağlayan bilim insanı aşağıdakilerden hangisidir?', '["Newton","Kopernik","Rousseau","Voltaire","Montesquieu"]', 1, 'Kopernik, Dünya''nın ve diğer gezegenlerin Güneş etrafında döndüğünü savunmuştur.', 1),
  ('Avrupa''da Değişim Çağı', 'Bilim Devrimi ve Aydınlanma', 'Evrensel çekim kanununu ortaya koyan bilim insanı aşağıdakilerden hangisidir?', '["Galileo","Kepler","Newton","Descartes","Voltaire"]', 2, 'Isaac Newton evrensel çekim kanununu ortaya koymuş, modern fiziğin gelişmesinde etkili olmuştur.', 1),
  ('Avrupa''da Değişim Çağı', 'Bilim Devrimi ve Aydınlanma', 'Toplum Sözleşmesi adlı eseriyle halk egemenliği düşüncesini savunan düşünür aşağıdakilerden hangisidir?', '["Rousseau","Machiavelli","Galileo","Kepler","Kopernik"]', 0, 'Rousseau, egemenliğin halka ait olduğunu savunmuş; fikirleri Fransız İhtilali üzerinde etkili olmuştur.', 2),
  ('Avrupa''da Değişim Çağı', 'Bilim Devrimi ve Aydınlanma', 'Aydınlanma Çağı''nın temel anlayışı aşağıdakilerden hangisidir?', '["Akıl ve bilimi esas almak","Din adamlarının otoritesini artırmak","Skolastik düşünceyi güçlendirmek","Feodaliteyi korumak","Mutlak monarşiyi yaymak"]', 0, 'Aydınlanma düşüncesinde akıl, bilim, özgürlük ve eşitlik kavramları öne çıkmıştır.', 2),
  ('Osmanlı Devleti''nde Değişim', 'Ekonomik Sarsıntı ve İltizam Sistemi', 'Osmanlı Devleti''nin vergi toplama hakkını belirli bir bedel karşılığında kişilere devretmesine dayanan sistem aşağıdakilerden hangisidir?', '["Tımar","İltizam","Devşirme","Müsadere","Narh"]', 1, 'İltizam sisteminde devlet, belirli bir vergi kaynağını toplama hakkını açık artırma yoluyla mültezimlere verirdi.', 1),
  ('Osmanlı Devleti''nde Değişim', 'Ekonomik Sarsıntı ve İltizam Sistemi', 'İltizam sisteminde vergi toplama hakkını devletten alan kişiye ne ad verilir?', '["Mültezim","Reaya","Tımarlı sipahi","Kadıköyü","Ayan"]', 0, 'Vergi toplama hakkını devletten alan ve belirlenen bedeli peşin ödeyen kişiye mültezim denirdi.', 1),
  ('Osmanlı Devleti''nde Değişim', 'Ekonomik Sarsıntı ve İltizam Sistemi', 'İltizam sisteminde vergi toplama hakkının ömür boyu verilmesine dayanan uygulama aşağıdakilerden hangisidir?', '["Malikâne","Müsadere","Dirlik","Gedik","Narh"]', 0, 'Malikâne sistemi, vergi kaynaklarının ömür boyu işletilmek üzere kişilere verilmesidir.', 2),
  ('Osmanlı Devleti''nde Değişim', 'Ekonomik Sarsıntı ve İltizam Sistemi', 'İltizam ve malikâne uygulamalarının yaygınlaşmasıyla taşrada güç kazanan yerel kişiler aşağıdakilerden hangisidir?', '["Ayanlar","Devşirmeler","Yeniçeriler","Kadılar","Şehzadeler"]', 0, 'Vergi kaynaklarını ve yerel gücü kontrol eden ayanlar, iltizam ve malikâne sistemleriyle taşrada daha etkili hâle gelmiştir.', 2),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 'Celâli İsyanları Osmanlı Devleti''nde ağırlıklı olarak hangi bölgede ortaya çıkmıştır?', '["Rumeli","Anadolu","Kırım","Mısır","Arabistan"]', 1, 'Celâli İsyanları, özellikle Anadolu''da görülen sosyal ve ekonomik temelli ayaklanmalardır.', 1),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 'Aşağıdakilerden hangisi Celâli İsyanlarının nedenlerinden biri değildir?', '["Ağır ve keyfî vergiler","Hızlı nüfus artışı ve kaynak yetersizliği","İşsizliğin artması","Devlet otoritesinin zayıflaması","Coğrafi Keşifler sonucu Amerika''nın bulunması"]', 4, 'Celâli İsyanlarında ağır vergiler, işsizlik, kaynak yetersizliği ve otorite zayıflığı etkili olmuştur. Amerika''nın bulunması doğrudan bir neden değildir.', 2),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 'Celâli İsyanları sonucunda Anadolu halkının güvenli bölgelere göç etmesine verilen ad aşağıdakilerden hangisidir?', '["Büyük Kaçgun","Kavimler Göçü","Hicret","Sürgün","İskân"]', 0, 'Celâli İsyanlarıyla birlikte Anadolu''da güvenlik bozulmuş, halkın göç hareketi Büyük Kaçgun olarak adlandırılmıştır.', 2),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 'Yeniçeri İsyanlarının Osmanlı Devleti üzerindeki en önemli etkilerinden biri aşağıdakilerden hangisidir?', '["Merkezî otoritenin güçlenmesi","Padişahların ve devlet adamlarının baskı altına alınması","Tımar sisteminin yaygınlaşması","Avrupa''daki toprakların genişlemesi","Halifeliğin Osmanlılara geçmesi"]', 1, 'Yeniçeri isyanları, merkezî otoriteyi zayıflatmış; padişah ve devlet adamları üzerinde baskı kurulmasına yol açmıştır.', 2),
  ('İsyanlar ve Düzeni Koruma', 'Celâli ve Yeniçeri İsyanları', 'Yeniçeriler tarafından öldürülen Osmanlı padişahı aşağıdakilerden hangisidir?', '["II. Osman","III. Selim","II. Mahmut","I. Ahmet","IV. Murat"]', 0, 'Genç Osman olarak da bilinen II. Osman, Yeniçeri İsyanı sırasında öldürülmüştür.', 1),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 'Ekber ve Erşed Sistemi''ne göre Osmanlı tahtına kimin geçmesi esastır?', '["Hanedanın en yaşlı ve en olgun üyesinin","Padişahın en büyük oğlunun","Divan üyelerinin seçtiği kişinin","Yeniçeri ağasının belirlediği şehzadenin","Halkın oyuyla seçilen kişinin"]', 0, 'Ekber ve Erşed Sistemi, hanedanın en yaşlı ve en olgun üyesinin tahta geçmesini esas alır.', 1),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 'Ekber ve Erşed Sistemi''nin kabul edilmesindeki temel amaç aşağıdakilerden hangisidir?', '["Devşirme sistemini yaygınlaştırmak","Taht kavgalarını azaltmak","Tımar sistemini kaldırmak","Halifeliği güçlendirmek","Avrupa''da fetihlere yeniden başlamak"]', 1, 'Sistem, hanedan içindeki taht mücadelelerini ve kardeş katli uygulamasını azaltmayı amaçlamıştır.', 2),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 'Lale Devri hangi antlaşmadan sonra başlamıştır?', '["Karlofça","Prut","Pasarofça","Belgrad","Küçük Kaynarca"]', 2, 'Lale Devri, 1718 Pasarofça Antlaşması''ndan sonra başlamıştır.', 1),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 'Lale Devri''nde ilk Türk matbaasını kuran kişi aşağıdakilerden hangisidir?', '["İbrahim Müteferrika","Katip Çelebi","Evliya Çelebi","Yirmisekiz Çelebi Mehmet Efendi","Koçi Bey"]', 0, 'İbrahim Müteferrika, Lale Devri''nde ilk Türk matbaasını kurmuştur.', 1),
  ('İsyanlar ve Düzeni Koruma', 'Ekber ve Erşed Sistemi ile Lale Devri', 'Lale Devri''nin sona ermesine yol açan isyan aşağıdakilerden hangisidir?', '["Kabakçı Mustafa İsyanı","Patrona Halil İsyanı","Celâli İsyanları","31 Mart Olayı","Alemdar Olayı"]', 1, 'Lale Devri, 1730 yılında Patrona Halil İsyanı ile sona ermiştir.', 2),
  ('İhtilaller Çağı', '1789 Fransız İhtilali', '1789 Fransız İhtilali sonucunda Fransa''da sona eren yönetim biçimi aşağıdakilerden hangisidir?', '["Mutlak monarşi","Cumhuriyet","Meşrutiyet","Federasyon","Oligarşi"]', 0, 'Fransız İhtilali ile Fransa''da mutlak monarşi yıkılmış ve cumhuriyet anlayışı güç kazanmıştır.', 1),
  ('İhtilaller Çağı', '1789 Fransız İhtilali', 'Aşağıdakilerden hangisi Fransız İhtilali''nin yaydığı temel düşüncelerden biri değildir?', '["Özgürlük","Eşitlik","Milliyetçilik","Demokrasi","Skolastik düşünce"]', 4, 'Fransız İhtilali özgürlük, eşitlik, milliyetçilik ve demokrasi fikirlerini yaymıştır; skolastik düşünceyi savunmamıştır.', 2),
  ('İhtilaller Çağı', '1789 Fransız İhtilali', 'Fransız İhtilali''nin milliyetçilik akımı yoluyla en fazla etkilediği siyasi yapılar aşağıdakilerden hangisidir?', '["Şehir devletleri","Çok uluslu imparatorluklar","Tek uluslu krallıklar","Ticaret şirketleri","Denizci devletler"]', 1, 'Milliyetçilik akımı, farklı milletleri bünyesinde barındıran çok uluslu imparatorluklarda ayrılıkçı hareketleri güçlendirmiştir.', 2),
  ('İhtilaller Çağı', '1789 Fransız İhtilali', 'Fransız İhtilali''nin Osmanlı Devleti üzerindeki en önemli etkisi aşağıdakilerden hangisidir?', '["Azınlık isyanlarının artması","Halifeliğin kaldırılması","İstanbul''un fethedilmesi","Tımar sisteminin kurulması","Devşirme sisteminin başlaması"]', 0, 'Milliyetçilik fikrinin yayılması, Osmanlı Devleti''ndeki Sırp ve Yunan isyanları gibi azınlık hareketlerini etkilemiştir.', 3),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Nizam-ı Cedit Ordusu', 'III. Selim döneminde Avrupa tarzında kurulan yeni askerî birlik aşağıdakilerden hangisidir?', '["Nizam-ı Cedit","Asakir-i Mansure","Yeniçeri Ocağı","Redif birlikleri","Tımarlı sipahiler"]', 0, 'Nizam-ı Cedit, III. Selim döneminde Batı tarzında eğitim ve talim yapan yeni askerî birliktir.', 1),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Nizam-ı Cedit Ordusu', 'Nizam-ı Cedit ordusunun giderlerini karşılamak amacıyla oluşturulan hazine aşağıdakilerden hangisidir?', '["İrad-ı Cedit","Hazine-i Hassa","Düyûn-ı Umûmiye","Mukataa Hazinesi","Cebehane Hazinesi"]', 0, 'Nizam-ı Cedit ordusunun masraflarını karşılamak için İrad-ı Cedit adı verilen özel hazine kurulmuştur.', 2),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Nizam-ı Cedit Ordusu', 'Nizam-ı Cedit ordusunun dağıtılmasına ve III. Selim''in tahttan indirilmesine yol açan gelişme aşağıdakilerden hangisidir?', '["Patrona Halil İsyanı","Kabakçı Mustafa İsyanı","Celâli İsyanları","31 Mart Olayı","Vaka-i Hayriye"]', 1, '1807 Kabakçı Mustafa İsyanı sonrasında III. Selim tahttan indirilmiş, Nizam-ı Cedit ordusu dağıtılmıştır.', 2),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Nizam-ı Cedit Ordusu', 'Alemdar Mustafa Paşa''nın Nizam-ı Cedit örnek alınarak kurduğu askerî birlik aşağıdakilerden hangisidir?', '["Sekban-ı Cedit","Asakir-i Mansure","Eşkinci Ocağı","Azaplar","Yaya ve müsellemler"]', 0, 'Alemdar Mustafa Paşa, Nizam-ı Cedit''i örnek alarak Sekban-ı Cedit Ocağı''nı kurmuştur.', 2),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Vakay-ı Hayriye ve Yeni Ordu', 'II. Mahmut döneminde Yeniçeri Ocağı''nın kaldırılması olayı aşağıdaki adlardan hangisiyle bilinir?', '["Vaka-i Vakvakiye","Vaka-i Hayriye","Kabakçı Mustafa İsyanı","Patrona Halil İsyanı","Alemdar Olayı"]', 1, 'Yeniçeri Ocağı''nın 1826''da kaldırılması, Hayırlı Olay anlamındaki Vaka-i Hayriye olarak adlandırılmıştır.', 1),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Vakay-ı Hayriye ve Yeni Ordu', 'Yeniçeri Ocağı kaldırıldıktan sonra kurulan yeni ve düzenli Osmanlı ordusu aşağıdakilerden hangisidir?', '["Nizam-ı Cedit","Sekban-ı Cedit","Asakir-i Mansure-i Muhammediye","Tımarlı Sipahiler","Akıncılar"]', 2, 'Yeniçeri Ocağı kaldırıldıktan sonra II. Mahmut tarafından Asakir-i Mansure-i Muhammediye ordusu kurulmuştur.', 1),
  ('Osmanlı Devleti''nde Modern Orduya Geçiş', 'Vakay-ı Hayriye ve Yeni Ordu', 'Vaka-i Hayriye''nin Osmanlı yenileşme hareketleri açısından en önemli sonucu aşağıdakilerden hangisidir?', '["Merkezî otoriteyi zayıflatması","Askerî yeniliklerin önündeki büyük engellerden birini kaldırması","Tımar sistemini yeniden başlatması","Avrupa''daki toprakları genişletmesi","Halifeliği kaldırması"]', 1, 'Yeniçeri Ocağı''nın kaldırılmasıyla askerî yeniliklere karşı en güçlü engellerden biri ortadan kalkmıştır.', 2),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Modern Eğitim Kurumları', 'II. Mahmut döneminde ortaöğretim düzeyinde açılan modern eğitim kurumları aşağıdakilerden hangisidir?', '["Enderunlar","Rüştiyeler","Nizamiye Medreseleri","Ahilik teşkilatları","Loncalar"]', 1, 'II. Mahmut döneminde modern eğitim anlayışı doğrultusunda rüştiyeler açılmıştır.', 1),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Modern Eğitim Kurumları', 'Osmanlı Devleti''nde yayımlanan ilk resmî gazete aşağıdakilerden hangisidir?', '["Ceride-i Havadis","Tercüman-ı Ahval","Takvim-i Vekayi","Tasvir-i Efkâr","İbret"]', 2, 'Takvim-i Vekayi, 1831 yılında yayımlanan ilk resmî Osmanlı gazetesidir.', 2),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Sosyal Devlet ve Simgeler', 'II. Mahmut dönemindeki kıyafet düzenlemeleriyle devlet memurlarının kullanması yaygınlaştırılan başlık aşağıdakilerden hangisidir?', '["Sarık","Fes","Börk","Külah","Kavuk"]', 1, 'II. Mahmut döneminde kıyafet düzenlemeleri yapılmış ve fes kullanımı yaygınlaştırılmıştır.', 1),
  ('XIX. Yüzyılda Sosyal Hayattaki Değişimler', 'Sosyal Devlet ve Simgeler', 'Salgın hastalıkların yayılmasını önlemek amacıyla oluşturulan kurum aşağıdakilerden hangisidir?', '["Mühendishane","Karantina teşkilatı","Enderun","Millet sistemi","Tımar sistemi"]', 1, 'XIX. yüzyılda salgınlarla mücadele etmek için karantina uygulamaları ve kurumları oluşturulmuştur.', 2),
  ('Osmanlı Devleti''ne Yönelik Tehditler-I', 'Sırp ve Yunan İsyanları', 'Milliyetçilik akımının etkisiyle başlayan Yunan İsyanı sonucunda Yunanistan''ın bağımsızlığı hangi antlaşmayla kabul edilmiştir?', '["Edirne Antlaşması","Karlofça Antlaşması","Küçük Kaynarca Antlaşması","Paris Antlaşması","Berlin Antlaşması"]', 0, '1829 Edirne Antlaşması ile Yunanistan bağımsızlığını kazanmıştır.', 1),
  ('Osmanlı Devleti''ne Yönelik Tehditler-I', 'Sırp ve Yunan İsyanları', 'II. Mahmut''un Mora İsyanı sırasında yardım istemesi, aşağıdaki kişilerden hangisinin güç kazanmasına ortam hazırlamıştır?', '["Kavalalı Mehmet Ali Paşa","Âlemdar Mustafa Paşa","Mithat Paşa","Fuad Paşa","Keçecizade Fuat Paşa"]', 0, 'II. Mahmut''un Mora İsyanı sırasında Mehmet Ali Paşa''dan yardım istemesi, onun Mısır''daki gücünü ve etkisini artırmıştır.', 2),
  ('Osmanlı Devleti''ne Yönelik Tehditler-II', 'Mehmet Ali Paşa ve Boğazlar', '1833 Hünkâr İskelesi Antlaşması Osmanlı Devleti ile hangi devlet arasında imzalanmıştır?', '["İngiltere","Rusya","Fransa","Avusturya","İran"]', 1, 'Mehmet Ali Paşa İsyanı sırasında Rusya''nın Osmanlı Devleti''ne yardım etmesinden sonra 1833 Hünkâr İskelesi Antlaşması imzalanmıştır.', 1),
  ('Osmanlı Devleti''ne Yönelik Tehditler-II', 'Mehmet Ali Paşa ve Boğazlar', 'Boğazların ilk kez uluslararası bir statü kazanmasını sağlayan gelişme aşağıdakilerden hangisidir?', '["Berlin Antlaşması","Londra Boğazlar Sözleşmesi","Karlofça Antlaşması","Paris Antlaşması","Balta Limanı Antlaşması"]', 1, '1841 Londra Boğazlar Sözleşmesi ile Boğazlar ilk kez uluslararası bir statü kazanmıştır.', 2),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Sened-i İttifak ve Tanzimat Fermanı', '1808 Sened-i İttifak''ın Osmanlı demokratikleşme tarihi açısından önemi aşağıdakilerden hangisidir?', '["İlk yazılı anayasa olması","Padişahın yetkilerini ilk kez hukuken sınırlaması","Cumhuriyetin ilan edilmesi","Halifeliğin kaldırılması","Çok partili hayata geçilmesi"]', 1, 'Sened-i İttifak, padişahın yetkilerini hukuken sınırlayan ilk siyasi belge kabul edilir.', 2),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Sened-i İttifak ve Tanzimat Fermanı', 'Sened-i İttifak ile varlıkları ve kazanımları resmen tanınan yerel güçler aşağıdakilerden hangisidir?', '["Yeniçeriler","Âyanlar","Mültezimler","Tımarlı sipahiler","Esnaflar"]', 1, 'Sened-i İttifak''ta âyanların varlığı ve bazı hakları resmen tanınmıştır.', 1),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Sened-i İttifak ve Tanzimat Fermanı', '1839 Tanzimat Fermanı ile güvence altına alınan haklar arasında aşağıdakilerden hangisi yer almaz?', '["Can güvenliği","Mal güvenliği","Namus güvenliği","Özel mülkiyetin tamamen kaldırılması","Hukuk önünde güvence"]', 3, 'Tanzimat Fermanı can, mal ve namus güvenliği sağlamayı amaçlamış; özel mülkiyeti kaldırmamıştır.', 2),
  ('Osmanlı Devleti''nde Demokratikleşme Hareketleri', 'Islahat Fermanı', '1856 Islahat Fermanı''nın özellikle haklarını genişlettiği kesim aşağıdakilerden hangisidir?', '["Tımarlı sipahiler","Yeniçeriler","Gayrimüslimler","Âyanlar","Mültezimler"]', 2, 'Islahat Fermanı, özellikle gayrimüslimlere yeni haklar tanımayı amaçlamıştır.', 1),
  ('Osmanlı Devleti''nde Darbeler', '1876 Darbesi ve 31 Mart Vakası', '1876''da ilan edilen Kanun-ı Esasi''nin Türk siyasi tarihi açısından önemi aşağıdakilerden hangisidir?', '["İlk siyasal parti olması","İlk yazılı anayasa olması","İlk cumhuriyet anayasası olması","Saltanatı kaldırması","Halifeliği sona erdirmesi"]', 1, 'Kanun-ı Esasi, Türk tarihinin ilk yazılı anayasasıdır ve I. Meşrutiyet Dönemi''ni başlatmıştır.', 1),
  ('Osmanlı Devleti''nde Darbeler', '1876 Darbesi ve 31 Mart Vakası', 'Kanun-ı Esasi döneminde Meclis-i Umumi''nin halk tarafından seçilen üyelerinin bulunduğu kanat aşağıdakilerden hangisidir?', '["Âyan Meclisi","Mebusan Meclisi","Divan-ı Hümayun","Şûra-yı Devlet","Meclis-i Vükela"]', 1, 'Meclis-i Mebusan üyeleri sınırlı da olsa halk tarafından seçimle belirlenirdi; Âyan Meclisi üyelerini padişah seçerdi.', 2),
  ('Osmanlı Devleti''nde Darbeler', '1876 Darbesi ve 31 Mart Vakası', 'II. Meşrutiyet''in ilan edilmesiyle yeniden yürürlüğe konan anayasa aşağıdakilerden hangisidir?', '["Tanzimat Fermanı","Islahat Fermanı","Kanun-ı Esasi","Sened-i İttifak","Teşkilat-ı Esasiye"]', 2, '1908''de II. Meşrutiyet ilan edilince Kanun-ı Esasi yeniden yürürlüğe konmuştur.', 1),
  ('Osmanlı Devleti''nde Darbeler', '1876 Darbesi ve 31 Mart Vakası', '31 Mart Olayı''nın bastırılmasından sonra meydana gelen gelişme aşağıdakilerden hangisidir?', '["II. Abdülhamid''in tahttan indirilmesi","Meşrutiyetin tamamen kaldırılması","Saltanatın kaldırılması","Osmanlı Devleti''nin savaşa girmesi","Cumhuriyetin ilan edilmesi"]', 0, '31 Mart Ayaklanması Hareket Ordusu tarafından bastırılmış; ardından II. Abdülhamid tahttan indirilmiştir.', 2),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Trablusgarp ve Balkan Savaşları', 'Trablusgarp Savaşı''nın başlamasına neden olan gelişme aşağıdakilerden hangisidir?', '["Fransa''nın Mısır''ı işgali","İtalya''nın Trablusgarp''a saldırması","Yunanistan''ın İzmir''i işgali","Rusya''nın Kırım''ı işgali","İngiltere''nin İstanbul''u işgali"]', 1, '1911 yılında İtalya''nın Trablusgarp''a saldırmasıyla savaş başlamıştır.', 1),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Trablusgarp ve Balkan Savaşları', 'Trablusgarp Savaşı sonunda Osmanlı Devleti''nin Trablusgarp ve Bingazi''yi İtalya''ya bırakmasına neden olan antlaşma aşağıdakilerden hangisidir?', '["Uşi Antlaşması","Edirne Antlaşması","Berlin Antlaşması","Bükreş Antlaşması","Mondros Ateşkesi"]', 0, 'Uşi Antlaşması ile Trablusgarp ve Bingazi İtalya''ya bırakılmıştır.', 2),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Trablusgarp ve Balkan Savaşları', 'I. Balkan Savaşı sonunda Osmanlı Devleti''nin Balkanlardaki sınırını belirleyen hat aşağıdakilerden hangisidir?', '["Midye-Enez hattı","Merinç-Arda hattı","Tuna-Sava hattı","Çatalca-Silivri hattı","Prut-Dinyester hattı"]', 0, '1912-1913 Balkan Savaşları sonunda Osmanlı Devleti, Midye-Enez hattının batısındaki topraklarını kaybetmiştir.', 2),
  ('20. Yüzyıl Başlarında Osmanlı Devleti', 'Trablusgarp ve Balkan Savaşları', 'II. Balkan Savaşı sırasında Osmanlı Devleti''nin geri aldığı şehirler aşağıdakilerden hangisidir?', '["İzmir ve Manisa","Edirne ve Kırklareli","Belgrad ve Semendire","Selanik ve Kavala","Üsküp ve Manastır"]', 1, 'II. Balkan Savaşı''ndan yararlanan Osmanlı Devleti, Edirne ve Kırklareli''yi geri almıştır.', 1),
