  ('Atatürk Dönemi''nde Yapılan İnkılaplar', 'Eğitim, Kültür ve Toplumsal İnkılaplar', 'Harf İnkılabı sonrasında yeni alfabeyi halka öğretmek amacıyla açılan kurumlar aşağıdakilerden hangisidir?', '["Halk Evleri","Millet Mektepleri","Nizamiye Medreseleri","Enderunlar","Rüştiyeler"]', 1, 'Harf İnkılabı''nın ardından okuma yazmayı yaygınlaştırmak amacıyla Millet Mektepleri açılmıştır.', 1)
) as d(unit_title, topic_title, prompt, options, correct_index, explanation, difficulty)
join public.units u on u.subject_id = 'tarih' and u.title = d.unit_title
join public.topics t on t.unit_id = u.id and t.title = d.topic_title;

